     1в†’/**
     2в†’ * MMS PM Scheduler Service - Tactical PM Scheduling
     3в†’ *
     4в†’ * Schedules preventive maintenance within a 12-week horizon, respecting:
     5в†’ * - Compliance windows (mileage OR time triggers)
     6в†’ * - PM hierarchy (C4 satisfies C1/C2/C3)
     7в†’ * - Track capability requirements
     8в†’ * - Material constraints (hard 14 days, soft 90 days)
     9в†’ * - Maximo lock status (INPRG work orders are read-only)
    10в†’ * - Service demand (fleet availability)
    11в†’ *
    12в†’ * Key business rules:
    13в†’ * - Compliance window: В±10% of interval (mileage or months)
    14в†’ * - PM hierarchy: Higher-level PMs satisfy lower-level requirements
    15в†’ * - Material hard constraint: BLOCKING parts must be available within 14 days
    16в†’ * - Material soft constraint: Warning if parts unavailable within 90 days
    17в†’ * - Track utilization target: 85%
    18в†’ * - Maximo lock: Cannot modify PM with INPRG work order
    19в†’ *
    20в†’ * @see specs/003-database-schema.md Section 3.5 (PM Management)
    21в†’ * @see specs/004-domain-services.md Section 4.4 (PM Scheduler)
    22в†’ */
    23в†’
    24в†’import { eq, and, sql, desc, inArray, gte, lte, isNull, count } from 'drizzle-orm';
    25в†’import type { SQL } from 'drizzle-orm';
