    59в†’import { getUnavailabilityService } from './unavailability';
    60в†’
    61в†’// =============================================================================
    62в†’// Types
    63в†’// =============================================================================
    64в†’
    65в†’/** Track type values */
    66в†’type TrackType = 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';
    67в†’
    68в†’/** Material criticality values */
    69в†’type MaterialCriticality = 'BLOCKING' | 'DEFERRABLE' | 'CONSUMABLE';
    70в†’
    71в†’/** Reservation type values */
    72в†’type ReservationType = 'SOFT' | 'HARD';
    73в†’
