    75в†’export interface PmDueResult {
    76в†’  pmTypeId: string;
    77в†’  pmCode: string;
    78в†’  pmName: string;
    79в†’  trainId: string;
    80в†’  trainNumber: string;
    81в†’  fleetId: string;
    82в†’  dueMileageKm: number | null;
    83в†’  dueDate: string | null;
    84в†’  currentMileageKm: number;
    85в†’  kmUntilDue: number | null;
    86в†’  daysUntilDue: number | null;
    87в†’  triggerType: 'MILEAGE' | 'TIME' | 'BOTH';
    88в†’  complianceWindow: ComplianceWindow;
    89в†’  isOverdue: boolean;
    90в†’  lastPmDate: string | null;
    91в†’  lastPmMileageKm: number | null;
    92в†’}
    93в†’
    94в†’/** Compliance window for scheduling */
    95в†’export interface ComplianceWindow {
    96в†’  startDate: string;
    97в†’  endDate: string;
    98в†’  startMileageKm: number | null;
    99в†’  endMileageKm: number | null;
   100в†’  idealDate: string;
