   160в†’
   161в†’/** Explanation trace for scheduling decisions */
   162в†’export interface SchedulingExplanation {
   163в†’  mileageTrigger: {
   164в†’    intervalKm: number | null;
   165в†’    currentMileageKm: number;
   166в†’    lastPmMileageKm: number | null;
   167в†’    kmSinceLastPm: number | null;
   168в†’    kmUntilDue: number | null;
   169в†’  };
   170в†’  timeTrigger: {
   171в†’    intervalMonths: number | null;
   172в†’    lastPmDate: string | null;
   173в†’    daysSinceLastPm: number | null;
