   181в†’  trackSelection: {
   182в†’    candidateTracks: number;
   183в†’    selectedTrackId: string | null;
   184в†’    selectionReason: string;
   185в†’  };
   186в†’  materialCheck: {
   187в†’    totalParts: number;
   188в†’    availableParts: number;
   189в†’    blockedParts: number;
   190в†’    warningParts: number;
   191в†’  };
   192в†’  constraints: string[];
   193в†’}
   194в†’
   195в†’/** Full scheduling result */
   196в†’export interface SchedulingResult {
   197в†’  horizonStart: string;
   198в†’  horizonEnd: string;
   199в†’  scheduled: SchedulingResultItem[];
   200в†’  deferred: SchedulingResultItem[];
   201в†’  blocked: SchedulingResultItem[];
   202в†’  materialWarnings: Array<{
   203в†’    trainId: string;
   204в†’    trainNumber: string;
   205в†’    pmCode: string;
   206в†’    targetDate: string;
   207в†’    warnings: MaterialAvailability[];
   208в†’  }>;
   209в†’  summary: {
   210в†’    totalProcessed: number;
   211в†’    totalScheduled: number;
   212в†’    totalDeferred: number;
   213в†’    totalBlocked: number;
   214в†’    trackUtilizationPct: number;
   215в†’  };
   216в†’}
   217в†’
   218в†’/** Request to schedule a PM */
   219в†’export interface SchedulePmRequest {
   220в†’  trainId: string;
   221в†’  pmTypeId: string;
   222в†’  targetDate: string;
   223в†’  assignedDepotId?: string;
   224в†’  assignedTrackId?: string;
   225в†’  assignedShift?: 'DAY' | 'NIGHT' | 'WEEKEND' | 'HOLIDAY';
   226в†’  notes?: string;
