   240в†’
   241в†’/** Request to run tactical scheduling */
   242в†’export interface TacticalScheduleRequest {
   243в†’  fleetId?: string;
   244в†’  depotId?: string;
   245в†’  horizonWeeks?: number;
   246в†’  dryRun?: boolean;
   247в†’  respectLocks?: boolean;
   248в†’}
   249в†’
   250в†’/** PM with details for scheduling */
   251в†’interface PmWithDetails extends PmScheduleRecord {
   252в†’  train: Train | null;
   253в†’  pmType: PmType | null;
   254в†’  assignedTrack: Track | null;
   255в†’}
   256в†’
   257в†’// =============================================================================
   258в†’// Constants
   259в†’// =============================================================================
   260в†’
   261в†’/** Default horizon for tactical scheduling (weeks) */
   262в†’const DEFAULT_HORIZON_WEEKS = 12;
   263в†’
   264в†’/** Hard material constraint window (days before PM) */
   265в†’const HARD_MATERIAL_WINDOW_DAYS = 14;
   266в†’
   267в†’/** Soft material constraint window (days before PM) */
   268в†’const SOFT_MATERIAL_WINDOW_DAYS = 90;
   269в†’
   270в†’/** Default daily mileage rate for projections (km) */
   271в†’const DEFAULT_DAILY_KM = 250;
   272в†’
   273в†’/** Default compliance tolerance percentage */
   274в†’const DEFAULT_TOLERANCE_PCT = 10;
   275в†’
   276в†’// =============================================================================
   277в†’// PM Scheduler Service
   278в†’// =============================================================================
   279в†’
   280в†’export class PMSchedulerService extends BaseService {
   281в†’  private serviceDemandService = getServiceDemandService();
   282в†’  private unavailabilityService = getUnavailabilityService();
   283в†’
   284в†’  constructor() {
   285в†’    super({ name: 'pm-scheduler-service', version: '1.0.0' });
   286в†’  }
   287в†’
   288в†’  // ===========================================================================
   289в†’  // Compliance Window Calculation
   290в†’  // ===========================================================================
   291в†’
   292в†’  /**
   293в†’   * Calculate compliance window for a PM type and train.
   294в†’   *
   295в†’   * The compliance window defines the valid date range for scheduling a PM.
   296в†’   * It is calculated based on:
   297в†’   * - Mileage trigger: intervalKm В± tolerance%
   298в†’   * - Time trigger: intervalMonths В± tolerance%
   299в†’   * - Whichever comes first determines the due date
   300в†’   *
   301в†’   * @param trainId - Train to calculate for
   302в†’   * @param pmTypeId - PM type to calculate for
   303в†’   * @returns Compliance window with start/end dates and mileage
   304в†’   */
   305в†’  async calculateComplianceWindow(
   306в†’    trainId: string,
   307в†’    pmTypeId: string
   308в†’  ): Promise<PmDueResult> {
   309в†’    return this.traced('calculateComplianceWindow', async (span) => {
   310в†’      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   311в†’      span.setAttribute('pm.typeId', pmTypeId);
   312в†’
   313в†’      // Get train details
   314в†’      const train = await this.db.query.trains.findFirst({
   315в†’        where: eq(trains.id, trainId),
   316в†’        with: { fleet: true },
   317в†’      });
   318в†’
   319в†’      if (!train) {
   320в†’        throw new TrainNotFoundError(trainId);
   321в†’      }
   322в†’
   323в†’      span.setAttribute(MmsAttributes.TRAIN_NUMBER, train.trainNumber);
   324в†’      span.setAttribute(MmsAttributes.FLEET_ID, train.fleetId);
   325в†’
   326в†’      // Get PM type details
   327в†’      const pmType = await this.db.query.pmTypes.findFirst({
   328в†’        where: and(
   329в†’          eq(pmTypes.id, pmTypeId),
   330в†’          eq(pmTypes.active, true)
   331в†’        ),
   332в†’      });
   333в†’
   334в†’      if (!pmType) {
   335в†’        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
   336в†’          entityType: 'pm_type',
   337в†’          entityId: pmTypeId,
   338в†’        });
   339в†’      }
   340в†’
   341в†’      // Get last completed PM of this type for this train
   342в†’      const lastPm = await this.getLastCompletedPm(trainId, pmTypeId);
   343в†’
   344в†’      // Check if a higher-level PM has satisfied this requirement
   345в†’      const hierarchySatisfied = await this.checkHierarchySatisfaction(
   346в†’        trainId,
   347в†’        pmType,
   348в†’        lastPm?.completedAt ?? null
   349в†’      );
   350в†’
   351в†’      // Use hierarchy satisfaction if more recent
   352в†’      const effectiveLastPm = hierarchySatisfied?.satisfiedByPm &&
   353в†’        (!lastPm || new Date(hierarchySatisfied.satisfiedByPm.completedAt ?? 0) > new Date(lastPm.completedAt ?? 0))
   354в†’        ? hierarchySatisfied.satisfiedByPm
   355в†’        : lastPm;
   356в†’
   357в†’      const lastPmDate = effectiveLastPm?.completedAt
   358в†’        ? new Date(effectiveLastPm.completedAt).toISOString().split('T')[0]
   359в†’        : train.commissioningDate ?? null;
   360в†’      const lastPmMileageKm = effectiveLastPm?.completedMileageKm ?? 0;
   361в†’
   362в†’      // Calculate due date and mileage
   363в†’      const currentMileageKm = train.currentMileageKm ?? 0;
   364в†’      const today = new Date();
   365в†’      const todayStr = today.toISOString().split('T')[0];
   366в†’
   367в†’      // Get early/late tolerance
   368в†’      const earlyTolerancePct = Number(pmType.earlyTolerancePct) || DEFAULT_TOLERANCE_PCT;
   369в†’      const lateTolerancePct = Number(pmType.lateTolerancePct) || DEFAULT_TOLERANCE_PCT;
   370в†’
   371в†’      // Calculate mileage trigger
   372в†’      let dueMileageKm: number | null = null;
   373в†’      let kmUntilDue: number | null = null;
   374в†’      let mileageWindowStart: number | null = null;
   375в†’      let mileageWindowEnd: number | null = null;
   376в†’
   377в†’      if (pmType.intervalKm) {
   378в†’        dueMileageKm = lastPmMileageKm + pmType.intervalKm;
   379в†’        kmUntilDue = dueMileageKm - currentMileageKm;
   380в†’
   381в†’        const toleranceKm = pmType.intervalKm * (earlyTolerancePct / 100);
   382в†’        mileageWindowStart = dueMileageKm - toleranceKm;
   383в†’        mileageWindowEnd = dueMileageKm + (pmType.intervalKm * (lateTolerancePct / 100));
   384в†’      }
   385в†’
   386в†’      // Calculate time trigger
   387в†’      let dueDate: string | null = null;
   388в†’      let daysUntilDue: number | null = null;
   389в†’      let dateWindowStart: string | null = null;
   390в†’      let dateWindowEnd: string | null = null;
   391в†’
   392в†’      if (pmType.intervalMonths && lastPmDate) {
   393в†’        const lastDate = new Date(lastPmDate);
   394в†’        const dueDateTime = new Date(lastDate);
   395в†’        dueDateTime.setMonth(dueDateTime.getMonth() + pmType.intervalMonths);
   396в†’        dueDate = dueDateTime.toISOString().split('T')[0];
   397в†’        daysUntilDue = Math.ceil((dueDateTime.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
   398в†’
   399в†’        const toleranceDays = Math.round((pmType.intervalMonths * 30) * (earlyTolerancePct / 100));
   400в†’        const lateDays = Math.round((pmType.intervalMonths * 30) * (lateTolerancePct / 100));
   401в†’
   402в†’        const windowStartDate = new Date(dueDateTime);
   403в†’        windowStartDate.setDate(windowStartDate.getDate() - toleranceDays);
   404в†’        dateWindowStart = windowStartDate.toISOString().split('T')[0];
   405в†’
   406в†’        const windowEndDate = new Date(dueDateTime);
   407в†’        windowEndDate.setDate(windowEndDate.getDate() + lateDays);
   408в†’        dateWindowEnd = windowEndDate.toISOString().split('T')[0];
   409в†’      }
   410в†’
   411в†’      // Determine trigger type (which comes first)
   412в†’      let triggerType: 'MILEAGE' | 'TIME' | 'BOTH' = 'BOTH';
   413в†’      let idealDate = todayStr;
   414в†’      let idealMileageKm = currentMileageKm;
   415в†’
   416в†’      if (dueMileageKm !== null && dueDate !== null) {
   417в†’        // Convert mileage due to date using daily rate
   418в†’        const dailyKm = await this.getAverageDailyKm(trainId);
   419в†’        const mileageDueDateMs = today.getTime() + ((kmUntilDue ?? 0) / dailyKm) * 24 * 60 * 60 * 1000;
   420в†’        const mileageDueDate = new Date(mileageDueDateMs);
   421в†’
   422в†’        const timeDueDate = new Date(dueDate);
   423в†’
   424в†’        if (mileageDueDate < timeDueDate) {
   425в†’          triggerType = 'MILEAGE';
   426в†’          idealDate = mileageDueDate.toISOString().split('T')[0];
   427в†’          idealMileageKm = dueMileageKm;
   428в†’        } else if (timeDueDate < mileageDueDate) {
   429в†’          triggerType = 'TIME';
   430в†’          idealDate = dueDate;
   431в†’          // Estimate mileage at time due date
   432в†’          const daysToTimeDue = Math.ceil((timeDueDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
   433в†’          idealMileageKm = currentMileageKm + (daysToTimeDue * dailyKm);
   434в†’        } else {
   435в†’          triggerType = 'BOTH';
   436в†’          idealDate = dueDate;
   437в†’          idealMileageKm = dueMileageKm;
   438в†’        }
   439в†’      } else if (dueMileageKm !== null) {
   440в†’        triggerType = 'MILEAGE';
   441в†’        const dailyKm = await this.getAverageDailyKm(trainId);
   442в†’        const mileageDueDateMs = today.getTime() + ((kmUntilDue ?? 0) / dailyKm) * 24 * 60 * 60 * 1000;
   443в†’        idealDate = new Date(mileageDueDateMs).toISOString().split('T')[0];
   444в†’        idealMileageKm = dueMileageKm;
   445в†’      } else if (dueDate !== null) {
   446в†’        triggerType = 'TIME';
   447в†’        idealDate = dueDate;
   448в†’        const dailyKm = await this.getAverageDailyKm(trainId);
   449в†’        const daysToTimeDue = Math.ceil((new Date(dueDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
   450в†’        idealMileageKm = currentMileageKm + (daysToTimeDue * dailyKm);
   451в†’      }
   452в†’
   453в†’      // Calculate compliance window dates
   454в†’      const dailyKm = await this.getAverageDailyKm(trainId);
   455в†’      let complianceStartDate = dateWindowStart ?? todayStr;
   456в†’      let complianceEndDate = dateWindowEnd ?? todayStr;
   457в†’
   458в†’      if (mileageWindowStart !== null) {
   459в†’        const kmToStart = mileageWindowStart - currentMileageKm;
   460в†’        const daysToStart = Math.max(0, Math.ceil(kmToStart / dailyKm));
   461в†’        const startDateFromMileage = new Date(today);
   462в†’        startDateFromMileage.setDate(startDateFromMileage.getDate() + daysToStart);
   463в†’
   464в†’        if (!dateWindowStart || startDateFromMileage < new Date(dateWindowStart)) {
   465в†’          complianceStartDate = startDateFromMileage.toISOString().split('T')[0];
   466в†’        }
   467в†’      }
   468в†’
   469в†’      if (mileageWindowEnd !== null) {
   470в†’        const kmToEnd = mileageWindowEnd - currentMileageKm;
   471в†’        const daysToEnd = Math.ceil(kmToEnd / dailyKm);
   472в†’        const endDateFromMileage = new Date(today);
   473в†’        endDateFromMileage.setDate(endDateFromMileage.getDate() + daysToEnd);
   474в†’
   475в†’        if (!dateWindowEnd || endDateFromMileage < new Date(dateWindowEnd)) {
   476в†’          complianceEndDate = endDateFromMileage.toISOString().split('T')[0];
   477в†’        }
   478в†’      }
   479в†’
   480в†’      // Ensure start date is not in the past
   481в†’      if (complianceStartDate < todayStr) {
   482в†’        complianceStartDate = todayStr;
   483в†’      }
   484в†’
   485в†’      // Check if overdue
   486в†’      const isOverdue = complianceEndDate < todayStr;
   487в†’
   488в†’      const result: PmDueResult = {
   489в†’        pmTypeId,
   490в†’        pmCode: pmType.pmCode,
   491в†’        pmName: pmType.pmName,
   492в†’        trainId,
   493в†’        trainNumber: train.trainNumber,
   494в†’        fleetId: train.fleetId,
   495в†’        dueMileageKm,
   496в†’        dueDate,
   497в†’        currentMileageKm,
   498в†’        kmUntilDue,
   499в†’        daysUntilDue,
   500в†’        triggerType,
   501в†’        complianceWindow: {
   502в†’          startDate: complianceStartDate,
   503в†’          endDate: complianceEndDate,
   504в†’          startMileageKm: mileageWindowStart,
   505в†’          endMileageKm: mileageWindowEnd,
   506в†’          idealDate,
   507в†’          idealMileageKm,
   508в†’        },
   509в†’        isOverdue,
   510в†’        lastPmDate,
   511в†’        lastPmMileageKm,
   512в†’      };
   513в†’
   514в†’      span.setAttribute('pm.triggerType', triggerType);
   515в†’      span.setAttribute('pm.isOverdue', isOverdue);
   516в†’      span.setAttribute('pm.kmUntilDue', kmUntilDue ?? -1);
   517в†’
   518в†’      return result;
   519в†’    });
   520в†’  }
   521в†’
   522в†’  /**
   523в†’   * Calculate PM due dates for all PM types for a train.
   524в†’   */
   525в†’  async calculateAllPmDue(trainId: string): Promise<PmDueResult[]> {
   526в†’    return this.traced('calculateAllPmDue', async (span) => {
   527в†’      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   528в†’
   529в†’      // Get train with fleet
   530в†’      const train = await this.db.query.trains.findFirst({
   531в†’        where: eq(trains.id, trainId),
   532в†’      });
   533в†’
   534в†’      if (!train) {
