   572в†’  /**
   573в†’   * Check if a higher-level PM has satisfied this PM type's requirement.
   574в†’   *
   575в†’   * PM Hierarchy: C4 satisfies C1/C2/C3, Overhaul satisfies all
   576в†’   */
   577в†’  private async checkHierarchySatisfaction(
   578в†’    trainId: string,
   579в†’    pmType: PmType,
   580в†’    sinceDate: Date | null
   581в†’  ): Promise<{ satisfiedBy: string | null; satisfiedByPm: PmScheduleRecord | null }> {
   582в†’    // Find PM types that satisfy this one
   583в†’    const satisfyingTypes = await this.db.query.pmTypes.findMany({
   584в†’      where: and(
   585в†’        eq(pmTypes.fleetId, pmType.fleetId),
   586в†’        eq(pmTypes.active, true),
   587в†’        sql`${pmType.pmCode} = ANY(${pmTypes.satisfiesCodes})`
   588в†’      ),
   589в†’    });
   590в†’
   591в†’    if (satisfyingTypes.length === 0) {
   592в†’      return { satisfiedBy: null, satisfiedByPm: null };
   593в†’    }
   594в†’
   595в†’    // Find the most recent completed PM of a satisfying type
   596в†’    const satisfyingTypeIds = satisfyingTypes.map(t => t.id);
   597в†’    const sinceDateFilter = sinceDate
   598в†’      ? gte(pmSchedule.completedAt, sinceDate)
   599в†’      : undefined;
   600в†’
   601в†’    const satisfyingPm = await this.db.query.pmSchedule.findFirst({
   602в†’      where: and(
   603в†’        eq(pmSchedule.trainId, trainId),
   604в†’        inArray(pmSchedule.pmTypeId, satisfyingTypeIds),
   605в†’        eq(pmSchedule.status, 'COMPLETED'),
   606в†’        isNull(pmSchedule.scenarioId),
   607в†’        sinceDateFilter
   608в†’      ),
   609в†’      orderBy: desc(pmSchedule.completedAt),
   610в†’    });
   611в†’
   612в†’    if (satisfyingPm) {
   613в†’      const satisfyingType = satisfyingTypes.find(t => t.id === satisfyingPm.pmTypeId);
   614в†’      return {
   615в†’        satisfiedBy: satisfyingType?.pmCode ?? null,
   616в†’        satisfiedByPm: satisfyingPm,
   617в†’      };
   618в†’    }
   619в†’
   620в†’    return { satisfiedBy: null, satisfiedByPm: null };
   621в†’  }
