   655в†’  /**
   656в†’   * Find suitable tracks for a PM based on type requirements.
   657в†’   */
   658в†’  async findSuitableTracks(
   659в†’    pmTypeId: string,
   660в†’    depotId: string | null,
   661в†’    targetDate: string,
   662в†’    durationDays: number
   663в†’  ): Promise<TrackAllocation[]> {
   664в†’    return this.traced('findSuitableTracks', async (span) => {
   665в†’      span.setAttribute('pm.typeId', pmTypeId);
   666в†’      span.setAttribute('pm.targetDate', targetDate);
   667в†’
   668в†’      // Get PM type requirements
   669в†’      const pmType = await this.db.query.pmTypes.findFirst({
   670в†’        where: eq(pmTypes.id, pmTypeId),
   671в†’      });
   672в†’
   673в†’      if (!pmType) {
   674в†’        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
   675в†’          entityType: 'pm_type',
   676в†’          entityId: pmTypeId,
   677в†’        });
   678в†’      }
   679в†’
   680в†’      // Get required capabilities for this PM type
   681в†’      const requiredCapabilities = await this.db.query.pmCapabilityRequirements.findMany({
   682в†’        where: eq(pmCapabilityRequirements.pmTypeId, pmTypeId),
   683в†’      });
   684в†’
   685в†’      const mandatoryCapabilities = requiredCapabilities
   686в†’        .filter(c => c.isMandatory)
   687в†’        .map(c => c.capability);
   688в†’
   689в†’      // Find tracks that match the track type
   690в†’      const trackConditions: SQL<unknown>[] = [
   691в†’        eq(tracks.trackType, pmType.trackType),
   692в†’        eq(tracks.active, true),
   693в†’      ];
   694в†’
   695в†’      if (depotId) {
   696в†’        trackConditions.push(eq(tracks.depotId, depotId));
   697в†’      }
   698в†’
   699в†’      const candidateTracks = await this.db.query.tracks.findMany({
   700в†’        where: and(...trackConditions),
   701в†’        with: {
   702в†’          depot: true,
   703в†’        },
   704в†’      });
   705в†’
   706в†’      // Check each track for capabilities and availability
   707в†’      const allocations: TrackAllocation[] = [];
   708в†’      const endDate = new Date(targetDate);
   709в†’      endDate.setDate(endDate.getDate() + durationDays - 1);
   710в†’      const endDateStr = endDate.toISOString().split('T')[0];
   711в†’
   712в†’      for (const track of candidateTracks) {
   713в†’        // Get track capabilities
   714в†’        const capabilities = await this.db.query.trackCapabilities.findMany({
   715в†’          where: and(
   716в†’            eq(trackCapabilities.trackId, track.id),
   717в†’            eq(trackCapabilities.isOperational, true)
   718в†’          ),
   719в†’        });
   720в†’
   721в†’        const trackCapabilitySet = new Set(capabilities.map(c => c.capability));
   722в†’
   723в†’        // Check mandatory capabilities
   724в†’        const missingCapabilities = mandatoryCapabilities.filter(
   725в†’          cap => !trackCapabilitySet.has(cap)
   726в†’        );
   727в†’
   728в†’        // Check availability (no conflicting PM)
   729в†’        const conflicts = await this.db.query.pmSchedule.findMany({
   730в†’          where: and(
   731в†’            eq(pmSchedule.assignedTrackId, track.id),
   732в†’            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
   733в†’            isNull(pmSchedule.scenarioId),
   734в†’            sql`${pmSchedule.targetDate} <= ${endDateStr}`,
   735в†’            sql`DATE(${pmSchedule.targetDate}) + COALESCE(
   736в†’              (SELECT min_track_days FROM pm_types WHERE id = ${pmSchedule.pmTypeId}), 1
   737в†’            ) > ${targetDate}`
   738в†’          ),
   739в†’        });
   740в†’
   741в†’        if (conflicts.length === 0) {
   742в†’          allocations.push({
   743в†’            trackId: track.id,
   744в†’            trackNumber: track.trackNumber,
   745в†’            depotId: track.depotId,
   746в†’            depotCode: track.depot?.code ?? 'unknown',
   747в†’            trackType: track.trackType as TrackType,
   748в†’            startDate: targetDate,
   749в†’            endDate: endDateStr,
   750в†’            hasAllCapabilities: missingCapabilities.length === 0,
   751в†’            missingCapabilities,
   752в†’          });
   753в†’        }
   754в†’      }
   755в†’
   756в†’      // Sort by capability match (prefer tracks with all capabilities)
   757в†’      allocations.sort((a, b) => {
   758в†’        if (a.hasAllCapabilities && !b.hasAllCapabilities) return -1;
   759в†’        if (!a.hasAllCapabilities && b.hasAllCapabilities) return 1;
   760в†’        return a.missingCapabilities.length - b.missingCapabilities.length;
   761в†’      });
   762в†’
   763в†’      span.setAttribute('result.trackCount', allocations.length);
   764в†’      return allocations;
   765в†’    });
   766в†’  }
