   810в†’
   811в†’  /**
   812в†’   * Check material availability for a PM.
   813в†’   *
   814в†’   * Material constraints:
   815в†’   * - Hard (14 days): BLOCKING parts must be available
   816в†’   * - Soft (90 days): Warning if parts unavailable
   817в†’   */
   818в†’  async checkMaterialAvailability(
   819в†’    pmTypeId: string,
   820в†’    depotId: string,
   821в†’    targetDate: string
   822в†’  ): Promise<MaterialConstraintResult> {
   823в†’    return this.traced('checkMaterialAvailability', async (span) => {
   824в†’      span.setAttribute('pm.typeId', pmTypeId);
   825в†’      span.setAttribute('depot.id', depotId);
   826в†’      span.setAttribute('pm.targetDate', targetDate);
   827в†’
   828в†’      // Get required materials for this PM type
   829в†’      const requirements = await this.db.query.pmMaterialRequirements.findMany({
   830в†’        where: eq(pmMaterialRequirements.pmTypeId, pmTypeId),
   831в†’      });
   832в†’
   833в†’      if (requirements.length === 0) {
   834в†’        return {
   835в†’          isBlocked: false,
   836в†’          hardConstraintViolations: [],
   837в†’          softConstraintWarnings: [],
   838в†’          totalMissingParts: 0,
   839в†’          reservations: [],
   840в†’        };
   841в†’      }
   842в†’
   843в†’      const today = new Date();
   844в†’      const pmDate = new Date(targetDate);
   845в†’      const daysUntilPm = Math.ceil((pmDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24));
   846в†’
   847в†’      const hardViolations: MaterialAvailability[] = [];
   848в†’      const softWarnings: MaterialAvailability[] = [];
   849в†’      const reservations: Array<{ partNumber: string; quantity: number; type: ReservationType }> = [];
   850в†’
   851в†’      for (const req of requirements) {
   852в†’        // Get inventory at the depot
   853в†’        const inventory = await this.db.query.inventoryPositions.findFirst({
   854в†’          where: and(
   855в†’            eq(inventoryPositions.depotId, depotId),
   856в†’            eq(inventoryPositions.partNumber, req.partNumber)
   857в†’          ),
   858в†’        });
   859в†’
   860в†’        const availableQty = inventory
   861в†’          ? (inventory.quantityOnHand ?? 0) - (inventory.quantityReserved ?? 0)
   862в†’          : 0;
   863в†’
   864в†’        const availability: MaterialAvailability = {
   865в†’          partNumber: req.partNumber,
   866в†’          partDescription: req.partDescription,
   867в†’          criticality: req.criticality as MaterialCriticality,
   868в†’          requiredQuantity: req.quantityPerPm,
   869в†’          availableQuantity: availableQty,
   870в†’          depotId,
   871в†’          isAvailable: availableQty >= req.quantityPerPm,
   872в†’          shortfall: Math.max(0, req.quantityPerPm - availableQty),
   873в†’          leadTimeDays: req.leadTimeDays ?? 14,
   874в†’          expectedAvailableDate: inventory?.nextDeliveryDate ?? null,
   875в†’        };
   876в†’
   877в†’        if (!availability.isAvailable) {
   878в†’          // Check if this is a hard or soft constraint violation
   879в†’          if (req.criticality === 'BLOCKING' && daysUntilPm <= HARD_MATERIAL_WINDOW_DAYS) {
   880в†’            hardViolations.push(availability);
   881в†’          } else if (daysUntilPm <= SOFT_MATERIAL_WINDOW_DAYS) {
   882в†’            softWarnings.push(availability);
   883в†’          }
   884в†’        }
   885в†’
   886в†’        // Create reservation record
   887в†’        if (availableQty >= req.quantityPerPm) {
   888в†’          reservations.push({
   889в†’            partNumber: req.partNumber,
   890в†’            quantity: req.quantityPerPm,
   891в†’            type: daysUntilPm <= HARD_MATERIAL_WINDOW_DAYS ? 'HARD' : 'SOFT',
   892в†’          });
   893в†’        }
   894в†’      }
   895в†’
   896в†’      const isBlocked = hardViolations.length > 0;
   897в†’
   898в†’      span.setAttribute('material.isBlocked', isBlocked);
   899в†’      span.setAttribute('material.hardViolations', hardViolations.length);
   900в†’      span.setAttribute('material.softWarnings', softWarnings.length);
   901в†’
   902в†’      return {
   903в†’        isBlocked,
   904в†’        hardConstraintViolations: hardViolations,
   905в†’        softConstraintWarnings: softWarnings,
   906в†’        totalMissingParts: hardViolations.length + softWarnings.length,
   907в†’        reservations,
   908в†’      };
   909в†’    });
   910в†’  }
