   996в†’      const train = await tx.query.trains.findFirst({
   997в†’        where: eq(trains.id, trainId),
   998в†’        with: { fleet: true, currentDepot: true },
   999в†’      });
  1000в†’
  1001в†’      if (!train) {
  1002в†’        throw new TrainNotFoundError(trainId);
  1003в†’      }
  1004в†’
  1005в†’      span.setAttribute(MmsAttributes.TRAIN_NUMBER, train.trainNumber);
  1006в†’
  1007в†’      // Get PM type
  1008в†’      const pmType = await tx.query.pmTypes.findFirst({
  1009в†’        where: eq(pmTypes.id, pmTypeId),
  1010в†’      });
  1011в†’
  1012в†’      if (!pmType) {
  1013в†’        throw new NotFoundError(`PM type not found: ${pmTypeId}`, {
  1014в†’          entityType: 'pm_type',
  1015в†’          entityId: pmTypeId,
  1016в†’        });
  1017в†’      }
  1018в†’
  1019в†’      // Calculate compliance window
  1020в†’      const dueResult = await this.calculateComplianceWindow(trainId, pmTypeId);
  1021в†’
  1022в†’      // Validate target date is within compliance window
  1023в†’      if (targetDate < dueResult.complianceWindow.startDate ||
  1024в†’          targetDate > dueResult.complianceWindow.endDate) {
  1025в†’        throw new ComplianceWindowError(
