  1034в†’
  1035в†’      // Check service demand (unless skipped)
  1036в†’      if (!skipServiceDemandCheck) {
  1037в†’        const { canSchedule, validation } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1038в†’          trainId,
