  1051в†’        }
  1052в†’      }
  1053в†’
  1054в†’      // Check unavailability
  1055в†’      const activeUnavailability = await this.unavailabilityService.getActiveEventsForTrain(trainId);
  1056в†’      const blockingEvent = activeUnavailability.find(e => e.blocksPmScheduling);
  1057в†’
  1058в†’      if (blockingEvent) {
  1059в†’        throw new BusinessRuleError(
  1060в†’          `Train ${train.trainNumber} has active unavailability blocking PM scheduling: ${blockingEvent.eventType}`,
  1061в†’          {
  1062в†’            rule: 'unavailability_blocks_pm',
  1063в†’            context: { eventId: blockingEvent.id, eventType: blockingEvent.eventType },
  1064в†’          }
  1065в†’        );
  1066в†’      }
  1067в†’
  1068в†’      // Determine depot
  1069в†’      const depotId = assignedDepotId ?? train.currentDepotId ?? train.homeDepotId;
  1070в†’      if (!depotId) {
  1071в†’        throw new ValidationError('No depot assigned and train has no current/home depot');
  1072в†’      }
  1073в†’
  1074в†’      // Check material availability (unless skipped)
  1075в†’      let materialResult: MaterialConstraintResult | null = null;
  1076в†’      if (!skipMaterialCheck) {
  1077в†’        materialResult = await this.checkMaterialAvailability(pmTypeId, depotId, targetDate);
  1078в†’
  1079в†’        if (materialResult.isBlocked) {
  1080в†’          const blockingParts = materialResult.hardConstraintViolations
  1081в†’            .map(v => v.partNumber)
  1082в†’            .join(', ');
  1083в†’
  1084в†’          throw new MaterialConstraintError(
  1085в†’            `Blocking materials not available: ${blockingParts}`,
  1086в†’            {
  1087в†’              partNumber: materialResult.hardConstraintViolations[0]?.partNumber,
  1088в†’              requiredQuantity: materialResult.hardConstraintViolations[0]?.requiredQuantity,
  1089в†’              availableQuantity: materialResult.hardConstraintViolations[0]?.availableQuantity,
  1090в†’            }
  1091в†’          );
  1092в†’        }
  1093в†’      }
  1094в†’
  1095в†’      // Find or validate track
  1096в†’      let trackId = assignedTrackId;
  1097в†’      if (!trackId) {
  1098в†’        const trackDuration = pmType.minTrackDays ?? 1;
  1099в†’        const suitableTracks = await this.findSuitableTracks(
  1100в†’          pmTypeId,
  1101в†’          depotId,
  1102в†’          targetDate,
  1103в†’          trackDuration
  1104в†’        );
  1105в†’
  1106в†’        if (suitableTracks.length > 0) {
  1107в†’          trackId = suitableTracks[0].trackId;
  1108в†’        }
  1109в†’      } else {
  1110в†’        // Validate provided track
  1111в†’        const conflict = await this.checkTrackConflict(
  1112в†’          trackId,
  1113в†’          targetDate,
  1114в†’          pmType.minTrackDays ?? 1
  1115в†’        );
  1116в†’
  1117в†’        if (conflict) {
  1118в†’          throw new TrackConflictError(
  1119в†’            `Track is already occupied on ${targetDate}`,
  1120в†’            {
  1121в†’              trackId,
  1122в†’              conflictingScheduleId: conflict.id,
  1123в†’            }
  1124в†’          );
  1125в†’        }
  1126в†’      }
  1127в†’
  1128в†’      // Estimate mileage at target date
  1129в†’      const dailyKm = await this.getAverageDailyKm(trainId);
  1130в†’      const today = new Date();
  1131в†’      const daysUntilTarget = Math.ceil(
  1132в†’        (new Date(targetDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
  1133в†’      );
  1134в†’      const targetMileageKm = (train.currentMileageKm ?? 0) + (daysUntilTarget * dailyKm);
  1135в†’
  1136в†’      // Create PM schedule record
  1137в†’      const pmData: NewPmScheduleRecord = {
  1138в†’        trainId,
  1139в†’        pmTypeId,
  1140в†’        targetDate,
  1141в†’        targetMileageKm: Math.round(targetMileageKm),
  1142в†’        status: 'SCHEDULED',
  1143в†’        constraintStart: dueResult.complianceWindow.startDate,
  1144в†’        constraintEnd: dueResult.complianceWindow.endDate,
  1145в†’        assignedDepotId: depotId,
  1146в†’        assignedTrackId: trackId ?? null,
  1147в†’        assignedHours: pmType.estimatedHours,
  1148в†’        assignedShift: assignedShift ?? null,
  1149в†’        createdBy: createdBy ?? null,
  1150в†’      };
  1151в†’
  1152в†’      const [created] = await tx.insert(pmSchedule).values(pmData).returning();
  1153в†’      span.setAttribute('pm.scheduleId', created.id);
  1154в†’
  1155в†’      // Create audit history record
  1156в†’      if (createdBy) {
  1157в†’        const historyRecord: NewPmScheduleHistory = {
  1158в†’          pmScheduleId: created.id,
  1159в†’          changeType: 'CREATED',
  1160в†’          newTargetDate: targetDate,
  1161в†’          newStatus: 'SCHEDULED',
  1162в†’          newAssignedTrackId: trackId ?? null,
  1163в†’          newAssignedHours: pmType.estimatedHours,
  1164в†’          changedBy: createdBy,
  1165в†’          changeReason: notes ?? 'PM scheduled',
  1166в†’          changeSource: 'USER',
  1167в†’        };
  1168в†’
  1169в†’        await tx.insert(pmScheduleHistory).values(historyRecord);
  1170в†’      }
  1171в†’
  1172в†’      // Create material reservations
  1173в†’      if (materialResult?.reservations && materialResult.reservations.length > 0) {
  1174в†’        for (const reservation of materialResult.reservations) {
  1175в†’          const inventory = await tx.query.inventoryPositions.findFirst({
  1176в†’            where: and(
  1177в†’              eq(inventoryPositions.depotId, depotId),
  1178в†’              eq(inventoryPositions.partNumber, reservation.partNumber)
  1179в†’            ),
  1180в†’          });
  1181в†’
  1182в†’          if (inventory) {
  1183в†’            await tx.insert(materialReservations).values({
  1184в†’              pmScheduleId: created.id,
  1185в†’              inventoryPositionId: inventory.id,
  1186в†’              partNumber: reservation.partNumber,
  1187в†’              quantityReserved: reservation.quantity,
  1188в†’              reservationType: reservation.type,
  1189в†’              reservedBy: createdBy ?? null,
  1190в†’              expiresAt: reservation.type === 'SOFT'
  1191в†’                ? new Date(Date.now() + 30 * 24 * 60 * 60 * 1000)
  1192в†’                : null,
  1193в†’            });
  1194в†’
  1195в†’            // Update inventory reserved quantity
  1196в†’            await tx
  1197в†’              .update(inventoryPositions)
  1198в†’              .set({
  1199в†’                quantityReserved: sql`${inventoryPositions.quantityReserved} + ${reservation.quantity}`,
  1200в†’              })
  1201в†’              .where(eq(inventoryPositions.id, inventory.id));
  1202в†’          }
  1203в†’        }
  1204в†’      }
  1205в†’
  1206в†’      this.log.info(
  1207в†’        {
  1208в†’          pmScheduleId: created.id,
  1209в†’          trainId,
  1210в†’          trainNumber: train.trainNumber,
  1211в†’          pmCode: pmType.pmCode,
  1212в†’          targetDate,
  1213в†’          trackId,
  1214в†’          depotId,
  1215в†’        },
  1216в†’        `PM scheduled: ${pmType.pmCode} for ${train.trainNumber} on ${targetDate}`
  1217в†’      );
  1218в†’
  1219в†’      return created;
  1220в†’    });
  1221в†’  }
