  1223в†’  /**
  1224в†’   * Move an existing PM to a new date.
  1225в†’   */
  1226в†’  async movePm(request: MovePmRequest): Promise<PmScheduleRecord> {
  1227в†’    return this.inTransaction('movePm', async (tx, span) => {
  1228в†’      const { pmScheduleId, newTargetDate, newTrackId, reason, movedBy } = request;
  1229в†’
  1230в†’      span.setAttribute('pm.scheduleId', pmScheduleId);
  1231в†’      span.setAttribute('pm.newTargetDate', newTargetDate);
  1232в†’
  1233в†’      // Get existing PM with relations
  1234в†’      const existingPm = await tx.query.pmSchedule.findFirst({
  1235в†’        where: eq(pmSchedule.id, pmScheduleId),
  1236в†’        with: {
  1237в†’          train: true,
  1238в†’          pmType: true,
  1239в†’          assignedTrack: true,
  1240в†’        },
  1241в†’      }) as PmWithDetails | null;
  1242в†’
  1243в†’      if (!existingPm) {
  1244в†’        throw new PmScheduleNotFoundError(pmScheduleId);
  1245в†’      }
  1246в†’
  1247в†’      // Check Maximo lock
  1248в†’      const lockStatus = await this.checkMaximoLock(pmScheduleId);
  1249в†’      if (lockStatus.isLocked) {
  1250в†’        throw new MaximoLockError(
  1251в†’          `PM cannot be moved: ${lockStatus.reason}`,
  1252в†’          {
  1253в†’            workOrderId: lockStatus.workOrderId ?? undefined,
  1254в†’            maximoStatus: lockStatus.maximoStatus ?? undefined,
  1255в†’          }
  1256в†’        );
  1257в†’      }
  1258в†’
  1259в†’      // Check status - only SCHEDULED can be moved
  1260в†’      if (existingPm.status !== 'SCHEDULED') {
  1261в†’        throw new BusinessRuleError(
  1262в†’          `PM cannot be moved: status is ${existingPm.status}`,
  1263в†’          {
  1264в†’            rule: 'pm_status_move',
  1265в†’            context: { currentStatus: existingPm.status },
  1266в†’          }
  1267в†’        );
  1268в†’      }
  1269в†’
  1270в†’      // Validate new date is within compliance window
  1271в†’      if (newTargetDate < existingPm.constraintStart ||
  1272в†’          newTargetDate > existingPm.constraintEnd) {
  1273в†’        throw new ComplianceWindowError(
  1274в†’          `New target date ${newTargetDate} is outside compliance window [${existingPm.constraintStart}, ${existingPm.constraintEnd}]`,
  1275в†’          {
  1276в†’            windowStart: new Date(existingPm.constraintStart),
  1277в†’            windowEnd: new Date(existingPm.constraintEnd),
  1278в†’            targetDate: new Date(newTargetDate),
  1279в†’          }
  1280в†’        );
  1281в†’      }
  1282в†’
  1283в†’      // Check service demand at new date
  1284в†’      const { canSchedule, validation } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1285в†’        existingPm.trainId,
  1286в†’        newTargetDate
  1287в†’      );
  1288в†’
  1289в†’      if (!canSchedule) {
  1290в†’        throw new ServiceDemandViolationError(
  1291в†’          validation.message,
  1292в†’          {
  1293в†’            fleetId: validation.fleetId,
  1294в†’            requiredTrains: validation.required,
  1295в†’            availableTrains: validation.availableTrains,
  1296в†’          }
  1297в†’        );
  1298в†’      }
  1299в†’
  1300в†’      // Handle track change
  1301в†’      let trackId = newTrackId ?? existingPm.assignedTrackId;
  1302в†’      if (trackId) {
  1303в†’        const conflict = await this.checkTrackConflict(
  1304в†’          trackId,
  1305в†’          newTargetDate,
  1306в†’          existingPm.pmType?.minTrackDays ?? 1,
  1307в†’          pmScheduleId
  1308в†’        );
  1309в†’
  1310в†’        if (conflict) {
  1311в†’          // Try to find alternative track
  1312в†’          if (!newTrackId) {
  1313в†’            const alternatives = await this.findSuitableTracks(
  1314в†’              existingPm.pmTypeId,
  1315в†’              existingPm.assignedDepotId,
  1316в†’              newTargetDate,
  1317в†’              existingPm.pmType?.minTrackDays ?? 1
  1318в†’            );
  1319в†’
  1320в†’            if (alternatives.length > 0) {
  1321в†’              trackId = alternatives[0].trackId;
  1322в†’            } else {
  1323в†’              trackId = null; // Clear track assignment
  1324в†’            }
  1325в†’          } else {
  1326в†’            throw new TrackConflictError(
  1327в†’              `Track is already occupied on ${newTargetDate}`,
  1328в†’              {
  1329в†’                trackId,
  1330в†’                conflictingScheduleId: conflict.id,
  1331в†’              }
  1332в†’            );
  1333в†’          }
  1334в†’        }
  1335в†’      }
  1336в†’
  1337в†’      // Calculate new target mileage
  1338в†’      const dailyKm = await this.getAverageDailyKm(existingPm.trainId);
  1339в†’      const today = new Date();
  1340в†’      const daysUntilTarget = Math.ceil(
  1341в†’        (new Date(newTargetDate).getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
  1342в†’      );
  1343в†’      const currentMileage = existingPm.train?.currentMileageKm ?? 0;
  1344в†’      const newTargetMileageKm = currentMileage + (daysUntilTarget * dailyKm);
  1345в†’
  1346в†’      // Record old values for history
  1347в†’      const oldTargetDate = existingPm.targetDate;
  1348в†’      const oldTrackId = existingPm.assignedTrackId;
  1349в†’
  1350в†’      // Update PM schedule
  1351в†’      const [updated] = await tx
  1352в†’        .update(pmSchedule)
  1353в†’        .set({
  1354в†’          targetDate: newTargetDate,
  1355в†’          targetMileageKm: Math.round(newTargetMileageKm),
  1356в†’          assignedTrackId: trackId,
  1357в†’          updatedAt: new Date(),
  1358в†’        })
  1359в†’        .where(eq(pmSchedule.id, pmScheduleId))
  1360в†’        .returning();
  1361в†’
  1362в†’      // Create audit history record
  1363в†’      const historyRecord: NewPmScheduleHistory = {
  1364в†’        pmScheduleId,
  1365в†’        changeType: 'DATE_CHANGED',
  1366в†’        oldTargetDate,
  1367в†’        newTargetDate,
  1368в†’        oldAssignedTrackId: oldTrackId,
  1369в†’        newAssignedTrackId: trackId,
  1370в†’        changedBy: movedBy,
  1371в†’        changeReason: reason,
  1372в†’        changeSource: 'USER',
  1373в†’      };
  1374в†’
  1375в†’      await tx.insert(pmScheduleHistory).values(historyRecord);
  1376в†’
  1377в†’      const trainNumber = existingPm.train?.trainNumber ?? 'unknown';
  1378в†’      const pmCode = existingPm.pmType?.pmCode ?? 'unknown';
  1379в†’
  1380в†’      this.log.info(
  1381в†’        {
  1382в†’          pmScheduleId,
  1383в†’          trainNumber,
  1384в†’          pmCode,
  1385в†’          oldTargetDate,
  1386в†’          newTargetDate,
  1387в†’          reason,
  1388в†’          movedBy,
  1389в†’        },
  1390в†’        `PM moved: ${pmCode} for ${trainNumber} from ${oldTargetDate} to ${newTargetDate}`
  1391в†’      );
  1392в†’
  1393в†’      return updated;
  1394в†’    });
  1395в†’  }
