  1431в†’        })
  1432в†’        .where(eq(pmSchedule.id, pmScheduleId))
  1433в†’        .returning();
  1434в†’
  1435в†’      // Create audit history
  1436в†’      const historyRecord: NewPmScheduleHistory = {
