  1443в†’
  1444в†’      await tx.insert(pmScheduleHistory).values(historyRecord);
  1445в†’
  1446в†’      this.log.info(
  1447в†’        { pmScheduleId, reason, lockedBy },
  1448в†’        `PM locked: ${pmScheduleId}`
  1449в†’      );
  1450в†’
  1451в†’      return updated;
  1452в†’    });
  1453в†’  }
