  1455в†’  /**
  1456в†’   * Unlock a PM to allow optimizer changes.
  1457в†’   */
  1458в†’  async unlockPm(pmScheduleId: string, unlockedBy: string): Promise<PmScheduleRecord> {
  1459в†’    return this.inTransaction('unlockPm', async (tx, span) => {
  1460в†’      span.setAttribute('pm.scheduleId', pmScheduleId);
  1461в†’
  1462в†’      const existing = await tx.query.pmSchedule.findFirst({
  1463в†’        where: eq(pmSchedule.id, pmScheduleId),
  1464в†’      });
  1465в†’
  1466в†’      if (!existing) {
