  1489в†’        .set({
  1490в†’          isLocked: false,
  1491в†’          lockedReason: null,
  1492в†’          lockedBy: null,
  1493в†’          lockedAt: null,
  1494в†’          updatedAt: new Date(),
  1495в†’        })
  1496в†’        .where(eq(pmSchedule.id, pmScheduleId))
  1497в†’        .returning();
  1498в†’
  1499в†’      // Create audit history
  1500в†’      const historyRecord: NewPmScheduleHistory = {
  1501в†’        pmScheduleId,
  1502в†’        changeType: 'UNLOCKED',
  1503в†’        changedBy: unlockedBy,
  1504в†’        changeReason: 'Manual unlock',
  1505в†’        changeSource: 'USER',
  1506в†’      };
  1507в†’
  1508в†’      await tx.insert(pmScheduleHistory).values(historyRecord);
  1509в†’
  1510в†’      this.log.info(
  1511в†’        { pmScheduleId, unlockedBy },
  1512в†’        `PM unlocked: ${pmScheduleId}`
  1513в†’      );
  1514в†’
  1515в†’      return updated;
  1516в†’    });
  1517в†’  }
