  1519в†’  // ===========================================================================
  1520в†’  // Tactical Scheduling Run
  1521в†’  // ===========================================================================
  1522в†’
  1523в†’  /**
  1524в†’   * Run tactical scheduling for the 12-week horizon.
  1525в†’   *
  1526в†’   * This method:
  1527в†’   * 1. Calculates PM due dates for all trains in scope
  1528в†’   * 2. Prioritizes by overdue status and due date
  1529в†’   * 3. Attempts to schedule each PM respecting constraints
  1530в†’   * 4. Returns a detailed result with scheduled, deferred, and blocked PMs
  1531в†’   */
  1532в†’  async runTacticalSchedule(request: TacticalScheduleRequest): Promise<SchedulingResult> {
  1533в†’    return this.traced('runTacticalSchedule', async (span) => {
  1534в†’      const {
  1535в†’        fleetId,
  1536в†’        depotId,
  1537в†’        horizonWeeks = DEFAULT_HORIZON_WEEKS,
  1538в†’        dryRun = false,
  1539в†’        respectLocks = true,
  1540в†’      } = request;
  1541в†’
  1542в†’      span.setAttribute('schedule.horizonWeeks', horizonWeeks);
  1543в†’      span.setAttribute('schedule.dryRun', dryRun);
  1544в†’
  1545в†’      const today = new Date();
  1546в†’      const horizonStart = today.toISOString().split('T')[0];
  1547в†’      const horizonEnd = new Date(today.getTime() + horizonWeeks * 7 * 24 * 60 * 60 * 1000)
  1548в†’        .toISOString()
  1549в†’        .split('T')[0];
  1550в†’
  1551в†’      // Get trains in scope
  1552в†’      const trainConditions: SQL<unknown>[] = [
  1553в†’        eq(trains.active, true),
  1554в†’        eq(trains.fitnessStatus, 'FIT'),
  1555в†’      ];
  1556в†’
  1557в†’      if (fleetId) {
  1558в†’        trainConditions.push(eq(trains.fleetId, fleetId));
  1559в†’      }
  1560в†’      if (depotId) {
  1561в†’        trainConditions.push(eq(trains.currentDepotId, depotId));
  1562в†’      }
  1563в†’
  1564в†’      const trainsInScope = await this.db.query.trains.findMany({
  1565в†’        where: and(...trainConditions),
  1566в†’        with: { fleet: true },
  1567в†’      });
  1568в†’
  1569в†’      span.setAttribute('schedule.trainsInScope', trainsInScope.length);
  1570в†’
  1571в†’      // Calculate PM due for all trains
  1572в†’      const allDueResults: PmDueResult[] = [];
  1573в†’
  1574в†’      for (const train of trainsInScope) {
  1575в†’        const dueResults = await this.calculateAllPmDue(train.id);
  1576в†’        allDueResults.push(...dueResults);
  1577в†’      }
  1578в†’
  1579в†’      // Filter to PMs due within horizon
  1580в†’      const pmsDueInHorizon = allDueResults.filter(pm =>
  1581в†’        pm.complianceWindow.startDate <= horizonEnd &&
  1582в†’        pm.complianceWindow.endDate >= horizonStart
  1583в†’      );
  1584в†’
  1585в†’      // Sort by priority (overdue first, then by due date)
  1586в†’      pmsDueInHorizon.sort((a, b) => {
  1587в†’        if (a.isOverdue && !b.isOverdue) return -1;
  1588в†’        if (!a.isOverdue && b.isOverdue) return 1;
  1589в†’        return a.complianceWindow.idealDate.localeCompare(b.complianceWindow.idealDate);
  1590в†’      });
  1591в†’
  1592в†’      span.setAttribute('schedule.pmsDueInHorizon', pmsDueInHorizon.length);
  1593в†’
  1594в†’      // Process each PM
  1595в†’      const scheduled: SchedulingResultItem[] = [];
  1596в†’      const deferred: SchedulingResultItem[] = [];
  1597в†’      const blocked: SchedulingResultItem[] = [];
  1598в†’      const materialWarnings: SchedulingResult['materialWarnings'] = [];
  1599в†’
  1600в†’      for (const pmDue of pmsDueInHorizon) {
  1601в†’        // Check if already scheduled
  1602в†’        const existingPm = await this.db.query.pmSchedule.findFirst({
  1603в†’          where: and(
  1604в†’            eq(pmSchedule.trainId, pmDue.trainId),
  1605в†’            eq(pmSchedule.pmTypeId, pmDue.pmTypeId),
  1606в†’            inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
  1607в†’            isNull(pmSchedule.scenarioId),
  1608в†’            gte(pmSchedule.targetDate, horizonStart),
  1609в†’            lte(pmSchedule.targetDate, horizonEnd)
  1610в†’          ),
  1611в†’        });
  1612в†’
  1613в†’        if (existingPm) {
  1614в†’          // Skip if locked and we're respecting locks
  1615в†’          if (respectLocks && existingPm.isLocked) {
  1616в†’            continue;
  1617в†’          }
  1618в†’        }
  1619в†’
  1620в†’        // Try to schedule
  1621в†’        const result = await this.attemptSchedulePm(pmDue, horizonEnd, dryRun);
  1622в†’
  1623в†’        if (result.status === 'SCHEDULED') {
  1624в†’          scheduled.push(result);
  1625в†’
  1626в†’          if (result.materialConstraint?.softConstraintWarnings.length) {
  1627в†’            materialWarnings.push({
  1628в†’              trainId: pmDue.trainId,
  1629в†’              trainNumber: pmDue.trainNumber,
  1630в†’              pmCode: pmDue.pmCode,
  1631в†’              targetDate: result.targetDate!,
  1632в†’              warnings: result.materialConstraint.softConstraintWarnings,
  1633в†’            });
  1634в†’          }
  1635в†’        } else if (result.status === 'DEFERRED') {
  1636в†’          deferred.push(result);
  1637в†’        } else {
  1638в†’          blocked.push(result);
  1639в†’        }
  1640в†’      }
  1641в†’
  1642в†’      // Calculate track utilization
  1643в†’      const trackUtilization = await this.calculateTrackUtilization(
  1644в†’        horizonStart,
  1645в†’        horizonEnd,
  1646в†’        depotId ?? null
  1647в†’      );
  1648в†’
  1649в†’      const summary = {
  1650в†’        totalProcessed: pmsDueInHorizon.length,
  1651в†’        totalScheduled: scheduled.length,
  1652в†’        totalDeferred: deferred.length,
  1653в†’        totalBlocked: blocked.length,
  1654в†’        trackUtilizationPct: trackUtilization,
  1655в†’      };
  1656в†’
  1657в†’      span.setAttribute('result.scheduled', scheduled.length);
  1658в†’      span.setAttribute('result.deferred', deferred.length);
  1659в†’      span.setAttribute('result.blocked', blocked.length);
  1660в†’      span.setAttribute('result.trackUtilization', trackUtilization);
  1661в†’
  1662в†’      this.log.info(
  1663в†’        {
  1664в†’          horizonStart,
  1665в†’          horizonEnd,
  1666в†’          ...summary,
  1667в†’          fleetId,
  1668в†’          depotId,
  1669в†’        },
  1670в†’        `Tactical scheduling complete: ${scheduled.length} scheduled, ${deferred.length} deferred, ${blocked.length} blocked`
  1671в†’      );
  1672в†’
  1673в†’      return {
  1674в†’        horizonStart,
  1675в†’        horizonEnd,
  1676в†’        scheduled,
  1677в†’        deferred,
  1678в†’        blocked,
  1679в†’        materialWarnings,
  1680в†’        summary,
  1681в†’      };
  1682в†’    });
  1683в†’  }
