  1685в†’  /**
  1686в†’   * Attempt to schedule a single PM within constraints.
  1687в†’   */
  1688в†’  private async attemptSchedulePm(
  1689в†’    pmDue: PmDueResult,
  1690в†’    horizonEnd: string,
  1691в†’    dryRun: boolean
  1692в†’  ): Promise<SchedulingResultItem> {
  1693в†’    const explanation: SchedulingExplanation = {
  1694в†’      mileageTrigger: {
  1695в†’        intervalKm: null,
  1696в†’        currentMileageKm: pmDue.currentMileageKm,
  1697в†’        lastPmMileageKm: pmDue.lastPmMileageKm,
  1698в†’        kmSinceLastPm: pmDue.lastPmMileageKm !== null
  1699в†’          ? pmDue.currentMileageKm - pmDue.lastPmMileageKm
  1700в†’          : null,
  1701в†’        kmUntilDue: pmDue.kmUntilDue,
  1702в†’      },
  1703в†’      timeTrigger: {
  1704в†’        intervalMonths: null,
  1705в†’        lastPmDate: pmDue.lastPmDate,
  1706в†’        daysSinceLastPm: pmDue.lastPmDate
  1707в†’          ? Math.floor((Date.now() - new Date(pmDue.lastPmDate).getTime()) / (1000 * 60 * 60 * 24))
  1708в†’          : null,
  1709в†’        daysUntilDue: pmDue.daysUntilDue,
  1710в†’      },
  1711в†’      hierarchySatisfied: {
  1712в†’        satisfiedBy: null,
  1713в†’        satisfiedOnDate: null,
  1714в†’        counterResetFrom: null,
  1715в†’      },
  1716в†’      trackSelection: {
  1717в†’        candidateTracks: 0,
  1718в†’        selectedTrackId: null,
  1719в†’        selectionReason: '',
  1720в†’      },
  1721в†’      materialCheck: {
  1722в†’        totalParts: 0,
  1723в†’        availableParts: 0,
  1724в†’        blockedParts: 0,
  1725в†’        warningParts: 0,
  1726в†’      },
  1727в†’      constraints: [],
  1728в†’    };
  1729в†’
  1730в†’    const warnings: string[] = [];
  1731в†’
  1732в†’    // Check unavailability
  1733в†’    const activeUnavailability = await this.unavailabilityService.getActiveEventsForTrain(pmDue.trainId);
  1734в†’    const blockingEvent = activeUnavailability.find(e => e.blocksPmScheduling);
  1735в†’
  1736в†’    if (blockingEvent) {
  1737в†’      explanation.constraints.push(`Blocked by unavailability: ${blockingEvent.eventType}`);
  1738в†’
  1739в†’      return {
  1740в†’        trainId: pmDue.trainId,
  1741в†’        trainNumber: pmDue.trainNumber,
  1742в†’        pmTypeId: pmDue.pmTypeId,
  1743в†’        pmCode: pmDue.pmCode,
  1744в†’        status: 'BLOCKED',
  1745в†’        targetDate: null,
  1746в†’        targetMileageKm: null,
  1747в†’        trackAllocation: null,
  1748в†’        materialConstraint: null,
  1749в†’        complianceWindow: pmDue.complianceWindow,
  1750в†’        deferralReason: `Train has active unavailability: ${blockingEvent.eventType}`,
  1751в†’        warnings,
  1752в†’        explanation,
  1753в†’      };
  1754в†’    }
  1755в†’
  1756в†’    // Determine ideal target date (within horizon)
  1757в†’    let targetDate = pmDue.complianceWindow.idealDate;
  1758в†’    if (targetDate > horizonEnd) {
  1759в†’      targetDate = horizonEnd;
  1760в†’    }
  1761в†’    if (targetDate < new Date().toISOString().split('T')[0]) {
  1762в†’      targetDate = new Date().toISOString().split('T')[0];
  1763в†’    }
  1764в†’
  1765в†’    // Check service demand
  1766в†’    const demandCheck = await this.serviceDemandService.canScheduleTrainForMaintenance(
  1767в†’      pmDue.trainId,
  1768в†’      targetDate
  1769в†’    );
  1770в†’
  1771в†’    if (!demandCheck.canSchedule) {
  1772в†’      // Try alternative dates within compliance window
  1773в†’      const alternativeDate = await this.findAlternativeDateForServiceDemand(
  1774в†’        pmDue.trainId,
  1775в†’        pmDue.complianceWindow.startDate,
  1776в†’        pmDue.complianceWindow.endDate
  1777в†’      );
  1778в†’
  1779в†’      if (!alternativeDate) {
  1780в†’        explanation.constraints.push(`Service demand violation: ${demandCheck.validation.message}`);
  1781в†’
  1782в†’        return {
  1783в†’          trainId: pmDue.trainId,
  1784в†’          trainNumber: pmDue.trainNumber,
  1785в†’          pmTypeId: pmDue.pmTypeId,
  1786в†’          pmCode: pmDue.pmCode,
  1787в†’          status: 'DEFERRED',
  1788в†’          targetDate: null,
  1789в†’          targetMileageKm: null,
  1790в†’          trackAllocation: null,
  1791в†’          materialConstraint: null,
  1792в†’          complianceWindow: pmDue.complianceWindow,
  1793в†’          deferralReason: demandCheck.validation.message,
  1794в†’          warnings,
  1795в†’          explanation,
  1796в†’        };
  1797в†’      }
  1798в†’
  1799в†’      targetDate = alternativeDate;
  1800в†’      warnings.push(`Rescheduled to ${alternativeDate} due to service demand constraints`);
  1801в†’    }
  1802в†’
  1803в†’    // Get train's depot
  1804в†’    const train = await this.db.query.trains.findFirst({
  1805в†’      where: eq(trains.id, pmDue.trainId),
  1806в†’    });
  1807в†’
  1808в†’    const depotId = train?.currentDepotId ?? train?.homeDepotId;
  1809в†’    if (!depotId) {
  1810в†’      explanation.constraints.push('No depot available for train');
  1811в†’
  1812в†’      return {
  1813в†’        trainId: pmDue.trainId,
  1814в†’        trainNumber: pmDue.trainNumber,
  1815в†’        pmTypeId: pmDue.pmTypeId,
  1816в†’        pmCode: pmDue.pmCode,
  1817в†’        status: 'BLOCKED',
  1818в†’        targetDate: null,
  1819в†’        targetMileageKm: null,
  1820в†’        trackAllocation: null,
  1821в†’        materialConstraint: null,
  1822в†’        complianceWindow: pmDue.complianceWindow,
  1823в†’        deferralReason: 'Train has no assigned depot',
  1824в†’        warnings,
  1825в†’        explanation,
  1826в†’      };
  1827в†’    }
  1828в†’
  1829в†’    // Get PM type for track duration
  1830в†’    const pmType = await this.db.query.pmTypes.findFirst({
  1831в†’      where: eq(pmTypes.id, pmDue.pmTypeId),
  1832в†’    });
  1833в†’
  1834в†’    const trackDuration = pmType?.minTrackDays ?? 1;
  1835в†’
  1836в†’    // Find suitable tracks
  1837в†’    const suitableTracks = await this.findSuitableTracks(
  1838в†’      pmDue.pmTypeId,
  1839в†’      depotId,
  1840в†’      targetDate,
  1841в†’      trackDuration
  1842в†’    );
  1843в†’
  1844в†’    explanation.trackSelection.candidateTracks = suitableTracks.length;
  1845в†’
  1846в†’    if (suitableTracks.length === 0) {
  1847в†’      explanation.constraints.push('No suitable tracks available');
  1848в†’      explanation.trackSelection.selectionReason = 'No tracks match requirements or all are occupied';
  1849в†’
  1850в†’      return {
  1851в†’        trainId: pmDue.trainId,
  1852в†’        trainNumber: pmDue.trainNumber,
  1853в†’        pmTypeId: pmDue.pmTypeId,
  1854в†’        pmCode: pmDue.pmCode,
  1855в†’        status: 'DEFERRED',
  1856в†’        targetDate: null,
  1857в†’        targetMileageKm: null,
  1858в†’        trackAllocation: null,
  1859в†’        materialConstraint: null,
  1860в†’        complianceWindow: pmDue.complianceWindow,
  1861в†’        deferralReason: 'No suitable tracks available',
  1862в†’        warnings,
  1863в†’        explanation,
  1864в†’      };
  1865в†’    }
  1866в†’
  1867в†’    const selectedTrack = suitableTracks[0];
  1868в†’    explanation.trackSelection.selectedTrackId = selectedTrack.trackId;
  1869в†’    explanation.trackSelection.selectionReason = selectedTrack.hasAllCapabilities
  1870в†’      ? 'Track has all required capabilities'
  1871в†’      : `Track missing: ${selectedTrack.missingCapabilities.join(', ')}`;
  1872в†’
  1873в†’    if (!selectedTrack.hasAllCapabilities) {
  1874в†’      warnings.push(`Selected track missing capabilities: ${selectedTrack.missingCapabilities.join(', ')}`);
  1875в†’    }
  1876в†’
  1877в†’    // Check material availability
  1878в†’    const materialResult = await this.checkMaterialAvailability(
  1879в†’      pmDue.pmTypeId,
  1880в†’      depotId,
  1881в†’      targetDate
  1882в†’    );
  1883в†’
  1884в†’    explanation.materialCheck.totalParts = materialResult.reservations.length +
  1885в†’      materialResult.hardConstraintViolations.length +
  1886в†’      materialResult.softConstraintWarnings.length;
  1887в†’    explanation.materialCheck.availableParts = materialResult.reservations.length;
  1888в†’    explanation.materialCheck.blockedParts = materialResult.hardConstraintViolations.length;
  1889в†’    explanation.materialCheck.warningParts = materialResult.softConstraintWarnings.length;
  1890в†’
  1891в†’    if (materialResult.isBlocked) {
  1892в†’      const blockingParts = materialResult.hardConstraintViolations
  1893в†’        .map(v => v.partNumber)
  1894в†’        .join(', ');
  1895в†’
  1896в†’      explanation.constraints.push(`Blocked by material constraint: ${blockingParts}`);
  1897в†’
  1898в†’      return {
  1899в†’        trainId: pmDue.trainId,
  1900в†’        trainNumber: pmDue.trainNumber,
  1901в†’        pmTypeId: pmDue.pmTypeId,
  1902в†’        pmCode: pmDue.pmCode,
  1903в†’        status: 'BLOCKED',
  1904в†’        targetDate: null,
  1905в†’        targetMileageKm: null,
  1906в†’        trackAllocation: selectedTrack,
  1907в†’        materialConstraint: materialResult,
  1908в†’        complianceWindow: pmDue.complianceWindow,
  1909в†’        deferralReason: `Blocking materials not available: ${blockingParts}`,
  1910в†’        warnings,
  1911в†’        explanation,
  1912в†’      };
  1913в†’    }
  1914в†’
  1915в†’    if (materialResult.softConstraintWarnings.length > 0) {
  1916в†’      const warningParts = materialResult.softConstraintWarnings
  1917в†’        .map(w => w.partNumber)
  1918в†’        .join(', ');
  1919в†’      warnings.push(`Material warning: ${warningParts} may not be available`);
  1920в†’    }
  1921в†’
  1922в†’    // Calculate target mileage
  1923в†’    const dailyKm = await this.getAverageDailyKm(pmDue.trainId);
  1924в†’    const daysUntilTarget = Math.ceil(
  1925в†’      (new Date(targetDate).getTime() - Date.now()) / (1000 * 60 * 60 * 24)
  1926в†’    );
  1927в†’    const targetMileageKm = pmDue.currentMileageKm + (daysUntilTarget * dailyKm);
  1928в†’
  1929в†’    // Create the PM schedule if not dry run
  1930в†’    if (!dryRun) {
  1931в†’      try {
  1932в†’        await this.schedulePm({
  1933в†’          trainId: pmDue.trainId,
  1934в†’          pmTypeId: pmDue.pmTypeId,
  1935в†’          targetDate,
  1936в†’          assignedDepotId: depotId,
  1937в†’          assignedTrackId: selectedTrack.trackId,
  1938в†’          skipMaterialCheck: true, // Already checked
  1939в†’          skipServiceDemandCheck: true, // Already checked
  1940в†’        });
  1941в†’      } catch (error) {
  1942в†’        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
  1943в†’        explanation.constraints.push(`Scheduling failed: ${errorMessage}`);
  1944в†’
  1945в†’        return {
  1946в†’          trainId: pmDue.trainId,
  1947в†’          trainNumber: pmDue.trainNumber,
  1948в†’          pmTypeId: pmDue.pmTypeId,
  1949в†’          pmCode: pmDue.pmCode,
  1950в†’          status: 'BLOCKED',
  1951в†’          targetDate: null,
  1952в†’          targetMileageKm: null,
  1953в†’          trackAllocation: selectedTrack,
  1954в†’          materialConstraint: materialResult,
  1955в†’          complianceWindow: pmDue.complianceWindow,
  1956в†’          deferralReason: errorMessage,
  1957в†’          warnings,
  1958в†’          explanation,
  1959в†’        };
  1960в†’      }
  1961в†’    }
  1962в†’
  1963в†’    return {
  1964в†’      trainId: pmDue.trainId,
  1965в†’      trainNumber: pmDue.trainNumber,
  1966в†’      pmTypeId: pmDue.pmTypeId,
  1967в†’      pmCode: pmDue.pmCode,
  1968в†’      status: 'SCHEDULED',
  1969в†’      targetDate,
  1970в†’      targetMileageKm: Math.round(targetMileageKm),
  1971в†’      trackAllocation: selectedTrack,
  1972в†’      materialConstraint: materialResult,
  1973в†’      complianceWindow: pmDue.complianceWindow,
  1974в†’      deferralReason: null,
  1975в†’      warnings,
  1976в†’      explanation,
  1977в†’    };
  1978в†’  }
