  2052в†’  /**
  2053в†’   * Get average daily km for a train from recent mileage readings.
  2054в†’   */
  2055в†’  private async getAverageDailyKm(trainId: string): Promise<number> {
  2056в†’    const thirtyDaysAgo = new Date();
  2057в†’    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
  2058в†’
  2059в†’    const readings = await this.db
  2060в†’      .select({
  2061в†’        avgDailyKm: sql<number>`AVG(${mileageReadings.dailyKm})`,
  2062в†’      })
  2063в†’      .from(mileageReadings)
  2064в†’      .where(
  2065в†’        and(
  2066в†’          eq(mileageReadings.trainId, trainId),
  2067в†’          gte(mileageReadings.readingDate, thirtyDaysAgo.toISOString().split('T')[0]),
  2068в†’          eq(mileageReadings.validationStatus, 'VALID')
  2069в†’        )
  2070в†’      );
  2071в†’
  2072в†’    return readings[0]?.avgDailyKm ?? DEFAULT_DAILY_KM;
  2073в†’  }
  2074в†’
  2075в†’  /**
  2076в†’   * Find an alternative date for scheduling when service demand blocks the ideal date.
  2077в†’   */
  2078в†’  private async findAlternativeDateForServiceDemand(
  2079в†’    trainId: string,
  2080в†’    windowStart: string,
  2081в†’    windowEnd: string
  2082в†’  ): Promise<string | null> {
  2083в†’    const start = new Date(windowStart);
  2084в†’    const end = new Date(windowEnd);
  2085в†’
  2086в†’    // Try each day in the window
  2087в†’    for (let d = start; d <= end; d.setDate(d.getDate() + 1)) {
  2088в†’      const dateStr = d.toISOString().split('T')[0];
  2089в†’      const { canSchedule } = await this.serviceDemandService.canScheduleTrainForMaintenance(
  2090в†’        trainId,
  2091в†’        dateStr
  2092в†’      );
  2093в†’
  2094в†’      if (canSchedule) {
  2095в†’        return dateStr;
  2096в†’      }
  2097в†’    }
  2098в†’
  2099в†’    return null;
  2100в†’  }
