  2102в†’  /**
  2103в†’   * Calculate track utilization percentage for a period.
  2104в†’   */
  2105в†’  private async calculateTrackUtilization(
  2106в†’    startDate: string,
  2107в†’    endDate: string,
  2108в†’    depotId: string | null
  2109в†’  ): Promise<number> {
  2110в†’    // Get total track-days available
  2111в†’    const trackConditions: SQL<unknown>[] = [
  2112в†’      eq(tracks.active, true),
  2113в†’      sql`${tracks.trackType} != 'STABLING'`,
  2114в†’    ];
  2115в†’
  2116в†’    if (depotId) {
  2117в†’      trackConditions.push(eq(tracks.depotId, depotId));
  2118в†’    }
  2119в†’
  2120в†’    const trackCount = await this.db
  2121в†’      .select({ count: count() })
  2122в†’      .from(tracks)
  2123в†’      .where(and(...trackConditions));
  2124в†’
  2125в†’    const totalTracks = trackCount[0]?.count ?? 0;
  2126в†’    const daysBetween = Math.ceil(
  2127в†’      (new Date(endDate).getTime() - new Date(startDate).getTime()) / (1000 * 60 * 60 * 24)
  2128в†’    );
  2129в†’    const totalTrackDays = totalTracks * daysBetween;
  2130в†’
  2131в†’    if (totalTrackDays === 0) return 0;
  2132в†’
  2133в†’    // Get scheduled PM track-days
  2134в†’    const pmConditions: SQL<unknown>[] = [
  2135в†’      inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
  2136в†’      isNull(pmSchedule.scenarioId),
  2137в†’      gte(pmSchedule.targetDate, startDate),
  2138в†’      lte(pmSchedule.targetDate, endDate),
  2139в†’      sql`${pmSchedule.assignedTrackId} IS NOT NULL`,
  2140в†’    ];
  2141в†’
  2142в†’    if (depotId) {
  2143в†’      pmConditions.push(eq(pmSchedule.assignedDepotId, depotId));
  2144в†’    }
