  2146в†’    const scheduledPms = await this.db.query.pmSchedule.findMany({
  2147в†’      where: and(...pmConditions),
  2148в†’      with: { pmType: true },
  2149в†’    });
  2150в†’
  2151в†’    const usedTrackDays = scheduledPms.reduce((sum, pm) => {
  2152в†’      const duration = pm.pmType?.minTrackDays ?? 1;
  2153в†’      return sum + duration;
  2154в†’    }, 0);
  2155в†’
  2156в†’    return Math.round((usedTrackDays / totalTrackDays) * 100);
  2157в†’  }
  2158в†’}
  2159в†’
  2160в†’// =============================================================================
  2161в†’// Singleton Export
