     1в†’/**
     2в†’ * MMS Man-hour Leveling Service
     3в†’ *
     4в†’ * Projects workforce requirements and generates adjustment recommendations
     5в†’ * to balance workload across time periods. Prevents overload/underutilization
     6в†’ * of depot maintenance resources over the tactical planning horizon.
     7в†’ *
     8в†’ * Key responsibilities:
     9в†’ * - Calculate raw man-hour projections from PM schedule
    10в†’ * - Identify overloaded and underutilized weeks
    11в†’ * - Apply leveling strategies in priority order
    12в†’ * - Persist projections and adjustments
    13в†’ * - Support approval workflow for adjustments
    14в†’ *
    15в†’ * Leveling Strategies (priority order):
    16в†’ * 1. ADVANCE_PM (1.1x cost, LOW risk, max 40h/week)
    17в†’ * 2. DEFER_PM (1.05x cost, LOW risk, max 40h/week)
    18в†’ * 3. ADD_OVERTIME (1.5x cost, NO risk, max 80h/week)
    19в†’ * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk, max 60h/week)
    20в†’ * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk, max 100h/week)
    21в†’ * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
    22в†’ *
    23в†’ * Utilization Targets:
    24в†’ * - Target: 85%
    25в†’ * - Minimum: 70% (underutilized below this)
    26в†’ * - Maximum: 100% (overloaded above this)
    27в†’ *
    28в†’ * @see specs/004-domain-services.md Section 4.6
    29в†’ */
    30в†’
    31в†’import {
    32в†’  eq,
    33в†’  and,
    34в†’  gte,
    35в†’  lte,
    36в†’  desc,
    37в†’  asc,
    38в†’  sql,
    39в†’  inArray,
    40в†’  isNull,
    41в†’  or,
    42в†’  count,
    43в†’  type SQL,
    44в†’} from 'drizzle-orm';
    45в†’import {
    46в†’  addDays,
    47в†’  addWeeks,
    48в†’  startOfWeek,
    49в†’  endOfWeek,
    50в†’  format,
    51в†’  differenceInWeeks,
    52в†’  parseISO,
    53в†’  isBefore,
    54в†’  isAfter,
    55в†’} from 'date-fns';
    56в†’import { BaseService } from '../lib/services/base';
    57в†’import {
    58в†’  manhourCapacity,
    59в†’  manhourProjections,
    60в†’  manhourAdjustments,
    61в†’  pmSchedule,
    62в†’  pmTypes,
    63в†’  depots,
    64в†’  trains,
    65в†’  laborRates,
    66в†’  type ManhourCapacity,
    67в†’  type ManhourProjection,
    68в†’  type ManhourAdjustment,
    69в†’} from '../lib/db/schema';
    70в†’import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';
    71в†’
    72в†’// =============================================================================
    73в†’// Constants
    74в†’// =============================================================================
    75в†’
    76в†’/** Minimum utilization percentage (underutilized below this) */
    77в†’const MIN_UTILIZATION = 0.7;
    78в†’
    79в†’/** Maximum utilization percentage (overloaded above this) */
    80в†’const MAX_UTILIZATION = 1.0;
    81в†’
    82в†’/** Default base labor rate per hour (SGD) */
    83в†’const DEFAULT_BASE_RATE = 85;
    84в†’
    85в†’/** Minimum meaningful shift in hours (don't bother with tiny adjustments) */
    86в†’const MIN_SHIFT_HOURS = 8;
    87в†’
    88в†’/** Minimum overtime hours to add */
    89в†’const MIN_OVERTIME_HOURS = 4;
    90в†’
    91в†’// =============================================================================
    92в†’// Types
    93в†’// =============================================================================
    94в†’
    95в†’/** Leveling strategy types */
    96в†’export type AdjustmentType =
    97в†’  | 'ADVANCE_PM'
    98в†’  | 'DEFER_PM'
    99в†’  | 'ADD_OVERTIME'
   100в†’  | 'CROSS_DEPOT'
   101в†’  | 'ADD_CONTRACTOR'
   102в†’  | 'MANUAL_REVIEW';
   103в†’
   104в†’/** Risk levels for adjustments */
   105в†’export type RiskLevel = 'NONE' | 'LOW' | 'MEDIUM' | 'HIGH';
   106в†’
   107в†’/** Adjustment status in workflow */
   108в†’export type AdjustmentStatus = 'PROPOSED' | 'APPROVED' | 'REJECTED' | 'APPLIED';
   109в†’
   110в†’/** Leveling strategy configuration */
   111в†’export interface LevelingStrategy {
   112в†’  type: AdjustmentType;
   113в†’  priority: number;
   114в†’  maxHoursPerWeek: number;
   115в†’  costMultiplier: number;
   116в†’  riskLevel: RiskLevel;
   117в†’}
   118в†’
   119в†’/** All leveling strategies in priority order */
   120в†’export const LEVELING_STRATEGIES: LevelingStrategy[] = [
   121в†’  { type: 'ADVANCE_PM', priority: 1, maxHoursPerWeek: 40, costMultiplier: 1.1, riskLevel: 'LOW' },
   122в†’  { type: 'DEFER_PM', priority: 2, maxHoursPerWeek: 40, costMultiplier: 1.05, riskLevel: 'LOW' },
   123в†’  { type: 'ADD_OVERTIME', priority: 3, maxHoursPerWeek: 80, costMultiplier: 1.5, riskLevel: 'NONE' },
   124в†’  { type: 'CROSS_DEPOT', priority: 4, maxHoursPerWeek: 60, costMultiplier: 1.3, riskLevel: 'MEDIUM' },
   125в†’  {
   126в†’    type: 'ADD_CONTRACTOR',
   127в†’    priority: 5,
   128в†’    maxHoursPerWeek: 100,
   129в†’    costMultiplier: 2.0,
   130в†’    riskLevel: 'MEDIUM',
   131в†’  },
   132в†’];
