   323в†’
   324в†’  /**
   325в†’   * Generate projections and leveling recommendations
   326в†’   *
   327в†’   * This is the main entry point for the leveling engine.
   328в†’   * It calculates raw projections, identifies imbalances, generates adjustments,
   329в†’   * and persists the results.
   330в†’   */
   331в†’  async generateProjections(request: GenerateProjectionsRequest = {}): Promise<LevelingResult> {
   332в†’    const horizonWeeks = request.horizonWeeks ?? 12;
   333в†’    const granularity = request.granularity ?? 'WEEKLY';
   334в†’
   335в†’    return this.traced(
   336в†’      'generateProjections',
   337в†’      async (span) => {
   338в†’        span.setAttribute('mms.manhour.horizon_weeks', horizonWeeks);
   339в†’        span.setAttribute('mms.manhour.granularity', granularity);
   340в†’
   341в†’        const runId = crypto.randomUUID();
   342в†’        span.setAttribute('mms.manhour.run_id', runId);
   343в†’
   344в†’        // 1. Get depots to process
   345в†’        const depotIds = await this.resolveDepotIds(request.depotIds);
   346в†’        if (depotIds.length === 0) {
   347в†’          throw new ValidationError('No depots found for projection');
   348в†’        }
   349в†’        span.setAttribute('mms.manhour.depot_count', depotIds.length);
   350в†’
   351в†’        // 2. Calculate raw projections
   352в†’        const rawProjections = await this.calculateRawProjections(
   353в†’          depotIds,
   354в†’          horizonWeeks,
   355в†’          granularity
   356в†’        );
   357в†’
   358в†’        // 3. Identify imbalances
   359в†’        const imbalances = this.identifyImbalances(rawProjections);
   360в†’        span.setAttribute('overloadedWeeks', imbalances.overloaded.length);
   361в†’        span.setAttribute('underutilizedWeeks', imbalances.underutilized.length);
   362в†’
   363в†’        // 4. Generate adjustments using multiple strategies
   364в†’        const adjustments = await this.generateAdjustments(rawProjections);
   365в†’        span.setAttribute('adjustmentCount', adjustments.length);
   366в†’
   367в†’        // 5. Apply adjustments to get leveled projections
   368в†’        const leveledProjections = this.applyAdjustments(rawProjections, adjustments);
   369в†’
   370в†’        // 6. Calculate metrics
   371в†’        const originalMetrics = this.calculateMetrics(rawProjections);
   372в†’        const leveledMetrics = this.calculateMetrics(leveledProjections);
   373в†’
   374в†’        // 7. Persist projections and adjustments
   375в†’        await this.persistProjections(runId, rawProjections, adjustments);
   376в†’
   377в†’        // 8. Build result
   378в†’        const improvement: LevelingImprovement = {
   379в†’          utilizationDelta: leveledMetrics.avgUtilization - originalMetrics.avgUtilization,
   380в†’          overloadedWeeksReduced: originalMetrics.overloadedWeeks - leveledMetrics.overloadedWeeks,
   381в†’          underutilizedWeeksReduced:
   382в†’            originalMetrics.underutilizedWeeks - leveledMetrics.underutilizedWeeks,
   383в†’          totalCostImpact: adjustments.reduce((sum, a) => sum + a.costImpact, 0),
   384в†’        };
   385в†’
   386в†’        this.log.info(
   387в†’          {
   388в†’            runId,
   389в†’            horizonWeeks,
   390в†’            depotCount: depotIds.length,
   391в†’            adjustmentCount: adjustments.length,
   392в†’            improvement,
   393в†’          },
   394в†’          'Generated man-hour projections'
   395в†’        );
   396в†’
   397в†’        return {
   398в†’          projectionRunId: runId,
   399в†’          generatedAt: new Date(),
   400в†’          horizonWeeks,
   401в†’          depotIds,
   402в†’          original: { projections: rawProjections, metrics: originalMetrics },
   403в†’          leveled: { projections: leveledProjections, metrics: leveledMetrics },
   404в†’          adjustments,
   405в†’          improvement,
   406в†’        };
   407в†’      },
   408в†’      { 'mms.manhour.requested_depots': request.depotIds?.length ?? 0 }
   409в†’    );
   410в†’  }
