   412в†’  /**
   413в†’   * Get projections for a specific depot and time range
   414в†’   */
   415в†’  async getProjections(
   416в†’    filters: ProjectionFilters,
   417в†’    page = 1,
   418в†’    pageSize = 50
   419в†’  ): Promise<PaginatedResult<ManhourProjection>> {
   420в†’    return this.traced('getProjections', async () => {
   421в†’      const conditions: SQL<unknown>[] = [];
   422в†’
   423в†’      if (filters.depotId) {
   424в†’        conditions.push(eq(manhourProjections.depotId, filters.depotId));
   425в†’      }
   426в†’      if (filters.fromDate) {
   427в†’        conditions.push(gte(manhourProjections.periodStart, format(filters.fromDate, 'yyyy-MM-dd')));
   428в†’      }
   429в†’      if (filters.toDate) {
   430в†’        conditions.push(lte(manhourProjections.periodEnd, format(filters.toDate, 'yyyy-MM-dd')));
   431в†’      }
   432в†’      if (filters.projectionRunId) {
   433в†’        conditions.push(eq(manhourProjections.projectionRunId, filters.projectionRunId));
   434в†’      }
   435в†’
   436в†’      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
   437в†’
   438в†’      const [projections, totalResult] = await Promise.all([
   439в†’        this.db.query.manhourProjections.findMany({
   440в†’          where: whereClause,
   441в†’          orderBy: [asc(manhourProjections.periodStart)],
   442в†’          limit: pageSize,
   443в†’          offset: (page - 1) * pageSize,
   444в†’        }),
   445в†’        this.db.select({ count: count() }).from(manhourProjections).where(whereClause),
   446в†’      ]);
   447в†’
   448в†’      return {
   449в†’        data: projections,
   450в†’        total: totalResult[0]?.count ?? 0,
   451в†’        page,
   452в†’        pageSize,
   453в†’      };
   454в†’    });
   455в†’  }
