   506в†’  /**
   507в†’   * Approve an adjustment
   508в†’   */
   509в†’  async approveAdjustment(adjustmentId: string, userId: string): Promise<ManhourAdjustment> {
   510в†’    return this.inTransaction('approveAdjustment', async (tx, span) => {
   511в†’      span.setAttribute('adjustmentId', adjustmentId);
   512в†’      span.setAttribute('userId', userId);
   513в†’
   514в†’      // Get adjustment
   515в†’      const adjustment = await tx.query.manhourAdjustments.findFirst({
   516в†’        where: eq(manhourAdjustments.id, adjustmentId),
   517в†’      });
   518в†’
   519в†’      if (!adjustment) {
   520в†’        throw new NotFoundError(`Adjustment ${adjustmentId} not found`);
   521в†’      }
   522в†’
   523в†’      if (adjustment.status !== 'PROPOSED') {
   524в†’        throw new ConflictError(
   525в†’          `Cannot approve adjustment in ${adjustment.status} status`,
   526в†’          { errorCode: 'ADJUSTMENT_STATUS_INVALID', currentStatus: adjustment.status }
   527в†’        );
   528в†’      }
   529в†’
   530в†’      // Update status
   531в†’      const [updated] = await tx
   532в†’        .update(manhourAdjustments)
   533в†’        .set({
   534в†’          status: 'APPROVED',
   535в†’          approvedBy: userId,
   536в†’          approvedAt: new Date(),
   537в†’        })
   538в†’        .where(eq(manhourAdjustments.id, adjustmentId))
   539в†’        .returning();
   540в†’
   541в†’      this.log.info({ adjustmentId, userId, type: adjustment.adjustmentType }, 'Adjustment approved');
   542в†’
   543в†’      return updated;
   544в†’    });
   545в†’  }
