   703в†’  private async calculateRawProjections(
   704в†’    depotIds: string[],
   705в†’    horizonWeeks: number,
   706в†’    granularity: 'WEEKLY' | 'MONTHLY'
   707в†’  ): Promise<ProjectionData[]> {
   708в†’    const projections: ProjectionData[] = [];
   709в†’    const now = new Date();
   710в†’    const startDate = startOfWeek(now, { weekStartsOn: 1 }); // Monday
   711в†’
   712в†’    // Get depot info
   713в†’    const depotList = await this.db.query.depots.findMany({
   714в†’      where: inArray(depots.id, depotIds),
   715в†’    });
   716в†’    const depotMap = new Map(depotList.map((d) => [d.id, d]));
   717в†’
   718в†’    for (const depotId of depotIds) {
   719в†’      const depot = depotMap.get(depotId);
   720в†’      if (!depot) continue;
   721в†’
   722в†’      // Get capacity for depot
   723в†’      const capacity = await this.getCapacity(depotId);
   724в†’      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
   725в†’
   726в†’      for (let weekOffset = 0; weekOffset < horizonWeeks; weekOffset++) {
   727в†’        const weekStart = addWeeks(startDate, weekOffset);
   728в†’        const weekEnd = endOfWeek(weekStart, { weekStartsOn: 1 });
   729в†’
   730в†’        // Get PM hours for this week
   731в†’        const pmHours = await this.getPmHoursForPeriod(depotId, weekStart, weekEnd);
   732в†’
   733в†’        // Calculate available hours
   734в†’        const regularHours = weeklyCapacity.regular;
   735в†’        const overtimeMax =
   736в†’          regularHours * (capacity ? parseFloat(capacity.maxOvertimePct ?? '20') / 100 : 0.2);
   737в†’
   738в†’        const required: RequiredHours = {
   739в†’          pm: pmHours,
   740в†’          corrective: 0, // TODO: Integrate with unavailability events
   741в†’          overhaul: 0, // TODO: Separate overhaul tracking
   742в†’          total: pmHours,
   743в†’        };
   744в†’
   745в†’        const available: AvailableHours = {
   746в†’          regular: regularHours,
   747в†’          overtime: overtimeMax,
   748в†’          total: regularHours + overtimeMax,
   749в†’        };
   750в†’
   751в†’        const variance = available.total - required.total;
   752в†’        const utilizationPct = available.total > 0 ? required.total / available.total : 0;
   753в†’
   754в†’        projections.push({
   755в†’          depotId,
   756в†’          depotCode: depot.code,
   757в†’          week: weekStart,
   758в†’          granularity,
   759в†’          required,
   760в†’          available,
   761в†’          variance,
   762в†’          utilizationPct,
   763в†’          isOverloaded: utilizationPct > MAX_UTILIZATION,
   764в†’          isUnderutilized: utilizationPct < MIN_UTILIZATION,
   765в†’        });
   766в†’      }
   767в†’    }
   768в†’
   769в†’    return projections;
   770в†’  }
   771в†’
   772в†’  /**
   773в†’   * Calculate weekly capacity from configuration
   774в†’   */
   775в†’  private calculateWeeklyCapacity(
   776в†’    capacity: ManhourCapacity | null
   777в†’  ): { regular: number; overtime: number } {
   778в†’    if (!capacity) {
   779в†’      // Default capacity when not configured
   780в†’      return { regular: 200, overtime: 40 };
   781в†’    }
   782в†’
   783в†’    const dayHours = parseFloat(capacity.dayShiftHours ?? '0');
   784в†’    const nightHours = parseFloat(capacity.nightShiftHours ?? '0');
   785в†’    const weekendHours = parseFloat(capacity.weekendHours ?? '0');
   786в†’    const maxOvertimePct = parseFloat(capacity.maxOvertimePct ?? '20') / 100;
   787в†’
   788в†’    const regular = dayHours * 5 + nightHours * 5 + weekendHours * 2;
   789в†’    const overtime = regular * maxOvertimePct;
   790в†’
   791в†’    return { regular, overtime };
   792в†’  }
