   794в†’  /**
   795в†’   * Get total PM hours for a time period
   796в†’   */
   797в†’  private async getPmHoursForPeriod(
   798в†’    depotId: string,
   799в†’    startDate: Date,
   800в†’    endDate: Date
   801в†’  ): Promise<number> {
   802в†’    const startStr = format(startDate, 'yyyy-MM-dd');
   803в†’    const endStr = format(endDate, 'yyyy-MM-dd');
   804в†’
   805в†’    // Get scheduled PMs for the period
   806в†’    const scheduledPMs = await this.db
   807в†’      .select({
   808в†’        pmTypeId: pmSchedule.pmTypeId,
   809в†’        count: count(),
   810в†’      })
   811в†’      .from(pmSchedule)
   812в†’      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
   813в†’      .where(
   814в†’        and(
   815в†’          eq(trains.currentDepotId, depotId),
   816в†’          gte(pmSchedule.targetDate, startStr),
   817в†’          lte(pmSchedule.targetDate, endStr),
   818в†’          eq(pmSchedule.status, 'SCHEDULED'),
   819в†’          isNull(pmSchedule.scenarioId) // Only real schedule, not scenarios
   820в†’        )
   821в†’      )
   822в†’      .groupBy(pmSchedule.pmTypeId);
   823в†’
   824в†’    if (scheduledPMs.length === 0) {
   825в†’      return 0;
   826в†’    }
   827в†’
   828в†’    // Get estimated hours for each PM type
   829в†’    const pmTypeIds = scheduledPMs.map((p) => p.pmTypeId);
   830в†’    const pmTypeHours = await this.db.query.pmTypes.findMany({
   831в†’      where: inArray(pmTypes.id, pmTypeIds),
   832в†’      columns: { id: true, estimatedHours: true },
   833в†’    });
   834в†’
   835в†’    const hoursMap = new Map(pmTypeHours.map((pt) => [pt.id, parseFloat(pt.estimatedHours ?? '0')]));
   836в†’
   837в†’    // Calculate total hours
   838в†’    let totalHours = 0;
   839в†’    for (const pm of scheduledPMs) {
   840в†’      const hours = hoursMap.get(pm.pmTypeId) ?? 0;
   841в†’      totalHours += hours * pm.count;
   842в†’    }
   843в†’
   844в†’    return totalHours;
   845в†’  }
