   849в†’  // ===========================================================================
   850в†’
   851в†’  /**
   852в†’   * Identify overloaded and underutilized weeks
   853в†’   */
   854в†’  private identifyImbalances(projections: ProjectionData[]): {
   855в†’    overloaded: ProjectionData[];
   856в†’    underutilized: ProjectionData[];
   857в†’  } {
   858в†’    return {
   859в†’      overloaded: projections.filter((p) => p.isOverloaded),
   860в†’      underutilized: projections.filter((p) => p.isUnderutilized),
   861в†’    };
   862в†’  }
