   864в†’  // ===========================================================================
   865в†’  // Private: Adjustment Generation
   866в†’  // ===========================================================================
   867в†’
   868в†’  /**
   869в†’   * Generate adjustments to level workload
   870в†’   */
   871в†’  private async generateAdjustments(
   872в†’    projections: ProjectionData[]
   873в†’  ): Promise<ProposedAdjustment[]> {
   874в†’    const adjustments: ProposedAdjustment[] = [];
   875в†’
   876в†’    // Group projections by depot
   877в†’    const byDepot = this.groupByDepot(projections);
   878в†’
   879в†’    for (const depotProjections of byDepot.values()) {
   880в†’      const overloaded = depotProjections.filter((p) => p.isOverloaded);
   881в†’      const underutilized = depotProjections.filter((p) => p.isUnderutilized);
   882в†’
   883в†’      // Track remaining capacity in underutilized weeks
   884в†’      const underutilizedCapacity = new Map(
   885в†’        underutilized.map((p) => [
   886в†’          p.week.toISOString(),
   887в†’          p.available.total - p.required.total,
   888в†’        ])
   889в†’      );
   890в†’
   891в†’      for (const overWeek of overloaded) {
   892в†’        let remainingExcess = overWeek.required.total - overWeek.available.total;
   893в†’
   894в†’        // Try each strategy in priority order
   895в†’        for (const strategy of LEVELING_STRATEGIES) {
   896в†’          if (remainingExcess <= 0) break;
   897в†’
   898в†’          const adjustment = await this.tryStrategy(
   899в†’            strategy,
   900в†’            overWeek,
   901в†’            underutilized,
   902в†’            underutilizedCapacity,
   903в†’            depotProjections,
   904в†’            remainingExcess
   905в†’          );
   906в†’
   907в†’          if (adjustment) {
   908в†’            adjustments.push(adjustment);
   909в†’            remainingExcess -= adjustment.hoursAdjusted;
   910в†’
   911в†’            // Update underutilized capacity if we used some
   912в†’            if (
   913в†’              adjustment.targetPeriod &&
   914в†’              (adjustment.type === 'ADVANCE_PM' || adjustment.type === 'DEFER_PM')
   915в†’            ) {
   916в†’              const key = adjustment.targetPeriod.start.toISOString();
   917в†’              const current = underutilizedCapacity.get(key) ?? 0;
   918в†’              underutilizedCapacity.set(key, current - adjustment.hoursAdjusted);
   919в†’            }
   920в†’          }
   921в†’        }
   922в†’
   923в†’        // If still overloaded, flag for manual review
   924в†’        if (remainingExcess > 0) {
   925в†’          adjustments.push({
   926в†’            type: 'MANUAL_REVIEW',
   927в†’            sourcePeriod: {
   928в†’              start: overWeek.week,
   929в†’              end: addDays(overWeek.week, 7),
   930в†’            },
   931в†’            hoursAdjusted: 0,
   932в†’            affectedPMs: [],
   933в†’            affectedTrains: [],
   934в†’            costImpact: 0,
   935в†’            riskLevel: 'HIGH',
   936в†’            reason: `Unable to resolve ${remainingExcess.toFixed(0)}h overload - requires manual intervention`,
   937в†’          });
   938в†’        }
   939в†’      }
   940в†’    }
   941в†’
   942в†’    return adjustments;
   943в†’  }
   944в†’
   945в†’  /**
   946в†’   * Try a specific leveling strategy
   947в†’   */
   948в†’  private async tryStrategy(
   949в†’    strategy: LevelingStrategy,
   950в†’    overloadedWeek: ProjectionData,
   951в†’    underutilizedWeeks: ProjectionData[],
   952в†’    underutilizedCapacity: Map<string, number>,
   953в†’    allProjections: ProjectionData[],
   954в†’    excessHours: number
   955в†’  ): Promise<ProposedAdjustment | null> {
   956в†’    const maxHours = Math.min(strategy.maxHoursPerWeek, excessHours);
   957в†’    const baseRate = await this.getBaseRate(overloadedWeek.depotId);
   958в†’
   959в†’    switch (strategy.type) {
   960в†’      case 'ADVANCE_PM':
   961в†’      case 'DEFER_PM':
   962в†’        return this.tryShiftPmStrategy(
   963в†’          strategy,
   964в†’          overloadedWeek,
   965в†’          underutilizedWeeks,
   966в†’          underutilizedCapacity,
   967в†’          maxHours,
   968в†’          baseRate
   969в†’        );
   970в†’
   971в†’      case 'ADD_OVERTIME':
   972в†’        return this.tryOvertimeStrategy(strategy, overloadedWeek, maxHours, baseRate);
   973в†’
   974в†’      case 'CROSS_DEPOT':
   975в†’        return this.tryCrossDepotStrategy(strategy, overloadedWeek, maxHours, baseRate);
   976в†’
   977в†’      case 'ADD_CONTRACTOR':
   978в†’        return this.tryContractorStrategy(strategy, overloadedWeek, maxHours, baseRate);
   979в†’
   980в†’      default:
   981в†’        return null;
   982в†’    }
   983в†’  }
   984в†’
   985в†’  /**
   986в†’   * Try ADVANCE_PM or DEFER_PM strategy
   987в†’   */
   988в†’  private async tryShiftPmStrategy(
   989в†’    strategy: LevelingStrategy,
   990в†’    overloadedWeek: ProjectionData,
   991в†’    underutilizedWeeks: ProjectionData[],
   992в†’    underutilizedCapacity: Map<string, number>,
   993в†’    maxHours: number,
   994в†’    baseRate: number
   995в†’  ): Promise<ProposedAdjustment | null> {
   996в†’    const direction = strategy.type === 'ADVANCE_PM' ? -1 : 1;
   997в†’
   998в†’    // Find candidate weeks (before for ADVANCE, after for DEFER)
   999в†’    const candidates = underutilizedWeeks
  1000в†’      .filter((w) => {
  1001в†’        const weekDiff = differenceInWeeks(w.week, overloadedWeek.week);
  1002в†’        const remainingCapacity = underutilizedCapacity.get(w.week.toISOString()) ?? 0;
  1003в†’        return (
  1004в†’          w.depotId === overloadedWeek.depotId &&
  1005в†’          weekDiff * direction > 0 &&
  1006в†’          Math.abs(weekDiff) <= 4 &&
  1007в†’          remainingCapacity > MIN_SHIFT_HOURS
  1008в†’        );
  1009в†’      })
  1010в†’      .sort(
  1011в†’        (a, b) =>
  1012в†’          Math.abs(differenceInWeeks(a.week, overloadedWeek.week)) -
  1013в†’          Math.abs(differenceInWeeks(b.week, overloadedWeek.week))
  1014в†’      );
  1015в†’
  1016в†’    for (const candidate of candidates) {
  1017в†’      const availableCapacity = underutilizedCapacity.get(candidate.week.toISOString()) ?? 0;
  1018в†’      const shiftHours = Math.min(maxHours, availableCapacity * 0.8);
  1019в†’
  1020в†’      if (shiftHours >= MIN_SHIFT_HOURS) {
  1021в†’        // Find PMs that can be shifted
  1022в†’        const shiftablePMs = await this.findShiftablePMs(
  1023в†’          overloadedWeek,
  1024в†’          candidate,
  1025в†’          shiftHours,
  1026в†’          strategy.type as 'ADVANCE_PM' | 'DEFER_PM'
  1027в†’        );
  1028в†’
  1029в†’        if (shiftablePMs.length > 0) {
  1030в†’          const actualHours = shiftablePMs.reduce((sum, pm) => sum + pm.estimatedHours, 0);
  1031в†’
  1032в†’          const weekNumSource = format(overloadedWeek.week, 'ww');
  1033в†’          const weekNumTarget = format(candidate.week, 'ww');
  1034в†’          const action = strategy.type === 'DEFER_PM' ? 'Defer' : 'Advance';
  1035в†’
  1036в†’          return {
  1037в†’            type: strategy.type,
  1038в†’            sourcePeriod: {
  1039в†’              start: overloadedWeek.week,
  1040в†’              end: addDays(overloadedWeek.week, 7),
  1041в†’            },
  1042в†’            targetPeriod: {
  1043в†’              start: candidate.week,
  1044в†’              end: addDays(candidate.week, 7),
  1045в†’            },
  1046в†’            hoursAdjusted: actualHours,
  1047в†’            affectedPMs: shiftablePMs.map((pm) => pm.id),
  1048в†’            affectedTrains: [...new Set(shiftablePMs.map((pm) => pm.trainId))],
  1049в†’            costImpact: actualHours * baseRate * (strategy.costMultiplier - 1),
  1050в†’            riskLevel: strategy.riskLevel,
  1051в†’            reason: `${action} ${actualHours.toFixed(0)}h (${shiftablePMs.length} PMs) from Week ${weekNumSource} to Week ${weekNumTarget}`,
  1052в†’          };
  1053в†’        }
  1054в†’      }
  1055в†’    }
  1056в†’
  1057в†’    return null;
  1058в†’  }
  1059в†’
  1060в†’  /**
  1061в†’   * Try ADD_OVERTIME strategy
  1062в†’   */
  1063в†’  private tryOvertimeStrategy(
  1064в†’    strategy: LevelingStrategy,
