  1168в†’  /**
  1169в†’   * Find PMs that can be shifted to another week
  1170в†’   */
  1171в†’  private async findShiftablePMs(
  1172в†’    fromWeek: ProjectionData,
  1173в†’    toWeek: ProjectionData,
  1174в†’    targetHours: number,
  1175в†’    strategy: 'ADVANCE_PM' | 'DEFER_PM'
  1176в†’  ): Promise<ShiftablePM[]> {
  1177в†’    const fromStart = format(fromWeek.week, 'yyyy-MM-dd');
  1178в†’    const fromEnd = format(addDays(fromWeek.week, 6), 'yyyy-MM-dd');
  1179в†’
  1180в†’    // Get PMs in the overloaded week
  1181в†’    const scheduledPMs = await this.db
  1182в†’      .select({
  1183в†’        id: pmSchedule.id,
  1184в†’        trainId: pmSchedule.trainId,
  1185в†’        pmTypeId: pmSchedule.pmTypeId,
  1186в†’        targetDate: pmSchedule.targetDate,
  1187в†’        constraintStart: pmSchedule.constraintStart,
  1188в†’        constraintEnd: pmSchedule.constraintEnd,
  1189в†’        isLocked: pmSchedule.isLocked,
  1190в†’      })
  1191в†’      .from(pmSchedule)
  1192в†’      .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
  1193в†’      .where(
  1194в†’        and(
  1195в†’          eq(trains.currentDepotId, fromWeek.depotId),
  1196в†’          gte(pmSchedule.targetDate, fromStart),
  1197в†’          lte(pmSchedule.targetDate, fromEnd),
  1198в†’          inArray(pmSchedule.status, ['SCHEDULED']), // Not CONFIRMED, IN_PROGRESS, or COMPLETED
  1199в†’          eq(pmSchedule.isLocked, false), // Not locked
  1200в†’          isNull(pmSchedule.scenarioId) // Real schedule
  1201в†’        )
  1202в†’      );
  1203в†’
  1204в†’    if (scheduledPMs.length === 0) {
  1205в†’      return [];
  1206в†’    }
  1207в†’
  1208в†’    // Get PM type info
  1209в†’    const pmTypeIds = [...new Set(scheduledPMs.map((p) => p.pmTypeId))];
  1210в†’    const pmTypeInfo = await this.db.query.pmTypes.findMany({
  1211в†’      where: inArray(pmTypes.id, pmTypeIds),
  1212в†’      columns: { id: true, pmCode: true, estimatedHours: true },
  1213в†’    });
  1214в†’    const typeMap = new Map(pmTypeInfo.map((pt) => [pt.id, pt]));
  1215в†’
  1216в†’    // Filter PMs that can be shifted to target week
  1217в†’    const shiftablePMs: ShiftablePM[] = [];
  1218в†’    let accumulatedHours = 0;
  1219в†’
  1220в†’    for (const pm of scheduledPMs) {
  1221в†’      if (accumulatedHours >= targetHours) break;
  1222в†’
  1223в†’      const pmType = typeMap.get(pm.pmTypeId);
  1224в†’      if (!pmType) continue;
  1225в†’
  1226в†’      const constraintStart = pm.constraintStart ? parseISO(pm.constraintStart) : null;
  1227в†’      const constraintEnd = pm.constraintEnd ? parseISO(pm.constraintEnd) : null;
  1228в†’
  1229в†’      // Check if target week is within compliance window
  1230в†’      const targetDate = strategy === 'ADVANCE_PM' ? toWeek.week : addDays(toWeek.week, 6);
  1231в†’
  1232в†’      const withinWindow =
  1233в†’        (!constraintStart || !isBefore(targetDate, constraintStart)) &&
  1234в†’        (!constraintEnd || !isAfter(targetDate, constraintEnd));
  1235в†’
  1236в†’      if (withinWindow) {
  1237в†’        const hours = parseFloat(pmType.estimatedHours ?? '0');
  1238в†’        shiftablePMs.push({
  1239в†’          id: pm.id,
  1240в†’          trainId: pm.trainId,
  1241в†’          pmTypeCode: pmType.pmCode,
  1242в†’          estimatedHours: hours,
  1243в†’          currentDate: parseISO(pm.targetDate),
  1244в†’          constraintStart: constraintStart ?? new Date(0),
  1245в†’          constraintEnd: constraintEnd ?? new Date(9999, 11, 31),
  1246в†’        });
  1247в†’        accumulatedHours += hours;
  1248в†’      }
  1249в†’    }
  1250в†’
  1251в†’    return shiftablePMs;
  1252в†’  }
  1253в†’
  1254в†’  /**
  1255в†’   * Find other depots with available capacity
  1256в†’   */
  1257в†’  private async findDepotsWithCapacity(
  1258в†’    week: Date,
  1259в†’    minHours: number,
  1260в†’    excludeDepotId: string
  1261в†’  ): Promise<DepotWithCapacity[]> {
  1262в†’    // Get all depots except the excluded one
  1263в†’    const otherDepots = await this.db.query.depots.findMany({
  1264в†’      where: sql`${depots.id} != ${excludeDepotId}`,
  1265в†’    });
  1266в†’
  1267в†’    const results: DepotWithCapacity[] = [];
  1268в†’
  1269в†’    for (const depot of otherDepots) {
  1270в†’      const capacity = await this.getCapacity(depot.id, week);
  1271в†’      if (!capacity) continue;
  1272в†’
  1273в†’      // Get PM hours for this depot/week
  1274в†’      const pmHours = await this.getPmHoursForPeriod(depot.id, week, addDays(week, 6));
  1275в†’
  1276в†’      // Calculate available capacity
  1277в†’      const weeklyCapacity = this.calculateWeeklyCapacity(capacity);
  1278в†’      const availableHours = weeklyCapacity.regular + weeklyCapacity.overtime - pmHours;
  1279в†’
  1280в†’      if (availableHours >= minHours) {
  1281в†’        results.push({
  1282в†’          depotId: depot.id,
  1283в†’          depotCode: depot.code,
  1284в†’          depotName: depot.name,
  1285в†’          availableHours: Math.min(availableHours, minHours),
  1286в†’        });
  1287в†’      }
  1288в†’    }
  1289в†’
  1290в†’    // Sort by available hours (descending)
  1291в†’    return results.sort((a, b) => b.availableHours - a.availableHours);
  1292в†’  }
  1293в†’
  1294в†’  /**
  1295в†’   * Get base labor rate for a depot
  1296в†’   */
  1297в†’  private async getBaseRate(depotId?: string): Promise<number> {
  1298в†’    if (!depotId) {
  1299в†’      return DEFAULT_BASE_RATE;
  1300в†’    }
  1301в†’
  1302в†’    const rate = await this.db.query.laborRates.findFirst({
  1303в†’      where: and(
  1304в†’        eq(laborRates.depotId, depotId),
  1305в†’        lte(laborRates.effectiveFrom, format(new Date(), 'yyyy-MM-dd')),
  1306в†’        or(isNull(laborRates.effectiveTo), gte(laborRates.effectiveTo, format(new Date(), 'yyyy-MM-dd')))
  1307в†’      ),
  1308в†’      orderBy: [desc(laborRates.effectiveFrom)],
  1309в†’    });
  1310в†’
  1311в†’    return rate ? parseFloat(rate.regularHourlyRate ?? String(DEFAULT_BASE_RATE)) : DEFAULT_BASE_RATE;
  1312в†’  }
  1313в†’
  1314в†’  // ===========================================================================
  1315в†’  // Private: Apply Adjustments & Calculate Metrics
  1316в†’  // ===========================================================================
  1317в†’
  1318в†’  /**
  1319в†’   * Apply adjustments to projections (simulation, not persisted)
  1320в†’   */
  1321в†’  private applyAdjustments(
  1322в†’    projections: ProjectionData[],
  1323в†’    adjustments: ProposedAdjustment[]
  1324в†’  ): ProjectionData[] {
  1325в†’    // Create deep copy
  1326в†’    const leveled = projections.map((p) => ({
  1327в†’      ...p,
  1328в†’      required: { ...p.required },
  1329в†’      available: { ...p.available },
  1330в†’    }));
  1331в†’
  1332в†’    // Build lookup by week
  1333в†’    const weekMap = new Map(leveled.map((p) => [p.week.toISOString(), p]));
  1334в†’
  1335в†’    for (const adj of adjustments) {
  1336в†’      if (adj.type === 'MANUAL_REVIEW') continue;
  1337в†’
  1338в†’      const sourceKey = adj.sourcePeriod.start.toISOString();
  1339в†’      const source = weekMap.get(sourceKey);
  1340в†’
  1341в†’      if (adj.type === 'ADVANCE_PM' || adj.type === 'DEFER_PM') {
  1342в†’        // Move hours from source to target
  1343в†’        if (source && adj.targetPeriod) {
  1344в†’          const targetKey = adj.targetPeriod.start.toISOString();
  1345в†’          const target = weekMap.get(targetKey);
  1346в†’
  1347в†’          if (target) {
  1348в†’            source.required.pm -= adj.hoursAdjusted;
  1349в†’            source.required.total -= adj.hoursAdjusted;
  1350в†’            target.required.pm += adj.hoursAdjusted;
  1351в†’            target.required.total += adj.hoursAdjusted;
  1352в†’          }
  1353в†’        }
  1354в†’      } else if (adj.type === 'ADD_OVERTIME') {
  1355в†’        // Increase available hours in source
  1356в†’        if (source) {
  1357в†’          // Overtime is already counted in available.total
  1358в†’          // No change needed to projected available hours
  1359в†’        }
  1360в†’      } else if (adj.type === 'CROSS_DEPOT' || adj.type === 'ADD_CONTRACTOR') {
  1361в†’        // Reduce required hours in source (work transferred out)
  1362в†’        if (source) {
  1363в†’          source.required.total -= adj.hoursAdjusted;
  1364в†’        }
  1365в†’      }
  1366в†’    }
  1367в†’
  1368в†’    // Recalculate metrics for all weeks
  1369в†’    for (const p of leveled) {
  1370в†’      p.variance = p.available.total - p.required.total;
  1371в†’      p.utilizationPct = p.available.total > 0 ? p.required.total / p.available.total : 0;
  1372в†’      p.isOverloaded = p.utilizationPct > MAX_UTILIZATION;
  1373в†’      p.isUnderutilized = p.utilizationPct < MIN_UTILIZATION;
  1374в†’    }
  1375в†’
  1376в†’    return leveled;
  1377в†’  }
  1378в†’
  1379в†’  /**
  1380в†’   * Calculate aggregate metrics
  1381в†’   */
  1382в†’  private calculateMetrics(projections: ProjectionData[]): LevelingMetrics {
  1383в†’    if (projections.length === 0) {
  1384в†’      return {
  1385в†’        avgUtilization: 0,
  1386в†’        minUtilization: 0,
  1387в†’        maxUtilization: 0,
  1388в†’        overloadedWeeks: 0,
  1389в†’        underutilizedWeeks: 0,
  1390в†’        totalRequiredHours: 0,
  1391в†’        totalAvailableHours: 0,
  1392в†’      };
  1393в†’    }
  1394в†’
  1395в†’    const utilizations = projections.map((p) => p.utilizationPct);
  1396в†’
  1397в†’    return {
  1398в†’      avgUtilization: utilizations.reduce((a, b) => a + b, 0) / utilizations.length,
  1399в†’      minUtilization: Math.min(...utilizations),
  1400в†’      maxUtilization: Math.max(...utilizations),
  1401в†’      overloadedWeeks: projections.filter((p) => p.isOverloaded).length,
  1402в†’      underutilizedWeeks: projections.filter((p) => p.isUnderutilized).length,
  1403в†’      totalRequiredHours: projections.reduce((sum, p) => sum + p.required.total, 0),
  1404в†’      totalAvailableHours: projections.reduce((sum, p) => sum + p.available.total, 0),
  1405в†’    };
  1406в†’  }
  1407в†’
  1408в†’  /**
  1409в†’   * Group projections by depot
  1410в†’   */
  1411в†’  private groupByDepot(projections: ProjectionData[]): Map<string, ProjectionData[]> {
  1412в†’    const result = new Map<string, ProjectionData[]>();
  1413в†’
  1414в†’    for (const p of projections) {
  1415в†’      const existing = result.get(p.depotId) ?? [];
  1416в†’      existing.push(p);
  1417в†’      result.set(p.depotId, existing);
  1418в†’    }
  1419в†’
  1420в†’    return result;
  1421в†’  }
  1422в†’
  1423в†’  // ===========================================================================
  1424в†’  // Private: Persistence
  1425в†’  // ===========================================================================
  1426в†’
  1427в†’  /**
  1428в†’   * Persist projections and adjustments to database
  1429в†’   */
  1430в†’  private async persistProjections(
  1431в†’    runId: string,
  1432в†’    projections: ProjectionData[],
  1433в†’    adjustments: ProposedAdjustment[]
  1434в†’  ): Promise<void> {
  1435в†’    await this.inTransaction('persistProjections', async (tx, span) => {
  1436в†’      span.setAttribute('projectionRunId', runId);
  1437в†’      span.setAttribute('projectionCount', projections.length);
  1438в†’      span.setAttribute('adjustmentCount', adjustments.length);
  1439в†’
  1440в†’      // Insert projections
  1441в†’      for (const p of projections) {
  1442в†’        const [inserted] = await tx
  1443в†’          .insert(manhourProjections)
  1444в†’          .values({
  1445в†’            projectionRunId: runId,
  1446в†’            depotId: p.depotId,
  1447в†’            periodStart: format(p.week, 'yyyy-MM-dd'),
  1448в†’            periodEnd: format(addDays(p.week, 6), 'yyyy-MM-dd'),
  1449в†’            granularity: p.granularity,
  1450в†’            requiredPmHours: String(p.required.pm),
  1451в†’            requiredCorrectiveHours: String(p.required.corrective),
  1452в†’            requiredOverhaulHours: String(p.required.overhaul),
  1453в†’            requiredTotalHours: String(p.required.total),
  1454в†’            availableRegularHours: String(p.available.regular),
  1455в†’            availableOvertimeHours: String(p.available.overtime),
  1456в†’            availableTotalHours: String(p.available.total),
  1457в†’          })
  1458в†’          .returning();
  1459в†’
  1460в†’        // Insert adjustments for this projection
  1461в†’        const projectionAdjustments = adjustments.filter(
  1462в†’          (a) =>
  1463в†’            a.sourcePeriod.start.toISOString() === p.week.toISOString() &&
  1464в†’            (!p.depotCode || a.sourcePeriod.start.toISOString() === p.week.toISOString())
  1465в†’        );
  1466в†’
  1467в†’        for (const adj of projectionAdjustments) {
  1468в†’          await tx.insert(manhourAdjustments).values({
  1469в†’            projectionId: inserted.id,
  1470в†’            adjustmentType: adj.type,
  1471в†’            sourcePeriodStart: format(adj.sourcePeriod.start, 'yyyy-MM-dd'),
  1472в†’            sourcePeriodEnd: format(adj.sourcePeriod.end, 'yyyy-MM-dd'),
  1473в†’            targetPeriodStart: adj.targetPeriod
  1474в†’              ? format(adj.targetPeriod.start, 'yyyy-MM-dd')
  1475в†’              : null,
  1476в†’            targetPeriodEnd: adj.targetPeriod ? format(adj.targetPeriod.end, 'yyyy-MM-dd') : null,
  1477в†’            hoursAdjusted: String(adj.hoursAdjusted),
  1478в†’            affectedPmIds: adj.affectedPMs,
  1479в†’            affectedTrainIds: adj.affectedTrains,
  1480в†’            costImpact: String(adj.costImpact),
  1481в†’            riskImpact: adj.riskLevel,
  1482в†’            reason: adj.reason,
  1483в†’            status: 'PROPOSED',
  1484в†’          });
  1485в†’        }
  1486в†’      }
  1487в†’    });
  1488в†’  }
