  1457в†’### 4.3.3 C++ Optimizer Core
  1458в†’
  1459в†’```cpp
  1460в†’// mms-optimizer/src/solver.cpp
  1461в†’
  1462в†’#include <ortools/sat/cp_model.h>
  1463в†’#include <nlohmann/json.hpp>
  1464в†’#include <vector>
  1465в†’#include <unordered_map>
  1466в†’
  1467в†’using namespace operations_research::sat;
  1468в†’using json = nlohmann::json;
  1469в†’
  1470в†’struct ExplanationFactor {
  1471в†’    std::string constraint_type;  // "HARD" or "SOFT"
  1472в†’    std::string constraint_name;
  1473в†’    double impact;
  1474в†’    std::string description;
  1475в†’};
  1476в†’
  1477в†’class MmsSolver {
  1478в†’public:
  1479в†’    json solve(const json& input) {
  1480в†’        CpModelBuilder model;
  1481в†’        std::string request_id = input["request_id"];
  1482в†’        
  1483в†’        auto trains = input["trains"];
  1484в†’        auto routes = input["routes"];
  1485в†’        auto config = input["config"];
  1486в†’        
  1487в†’        // Decision variables: assign[t][r] = 1 if train t assigned to route r
  1488в†’        std::vector<std::vector<BoolVar>> assign;
  1489в†’        assign.resize(trains.size());
  1490в†’        
  1491в†’        for (size_t t = 0; t < trains.size(); t++) {
  1492в†’            assign[t].resize(routes.size());
  1493в†’            for (size_t r = 0; r < routes.size(); r++) {
  1494в†’                assign[t][r] = model.NewBoolVar();
  1495в†’            }
  1496в†’        }
  1497в†’        
  1498в†’        // Hard constraint: Each train assigned to at most one route
  1499в†’        for (size_t t = 0; t < trains.size(); t++) {
  1500в†’            std::vector<BoolVar> train_routes;
  1501в†’            for (size_t r = 0; r < routes.size(); r++) {
  1502в†’                train_routes.push_back(assign[t][r]);
  1503в†’            }
  1504в†’            model.AddAtMostOne(train_routes);
  1505в†’        }
  1506в†’        
  1507в†’        // Hard constraint: Route requirements (exactly N trains)
  1508в†’        for (size_t r = 0; r < routes.size(); r++) {
  1509в†’            std::vector<BoolVar> route_trains;
  1510в†’            for (size_t t = 0; t < trains.size(); t++) {
  1511в†’                // Check fleet compatibility
  1512в†’                if (isFleetAllowed(trains[t], routes[r])) {
  1513в†’                    route_trains.push_back(assign[t][r]);
  1514в†’                }
  1515в†’            }
  1516в†’            
  1517в†’            int required = routes[r]["required_trains"];
  1518в†’            model.AddEquality(LinearExpr::Sum(route_trains), required);
  1519в†’        }
  1520в†’        
  1521в†’        // Hard constraint: Fitness status
  1522в†’        for (size_t t = 0; t < trains.size(); t++) {
  1523в†’            if (trains[t]["fitness_status"] != "FIT") {
  1524в†’                for (size_t r = 0; r < routes.size(); r++) {
  1525в†’                    model.AddEquality(assign[t][r], 0);
  1526в†’                }
  1527в†’            }
  1528в†’        }
  1529в†’        
  1530в†’        // Hard constraints from input
  1531в†’        for (const auto& constraint : input["hard_constraints"]) {
  1532в†’            size_t train_idx = findTrainIndex(trains, constraint["train_id"]);
  1533в†’            if (train_idx < trains.size()) {
  1534в†’                for (size_t r = 0; r < routes.size(); r++) {
  1535в†’                    model.AddEquality(assign[train_idx][r], 0);
  1536в†’                }
  1537в†’            }
  1538в†’        }
  1539в†’        
  1540в†’        // NEW v2.1: Hard constraint - Unavailability events
  1541в†’        if (input.contains("unavailability_events")) {
  1542в†’            for (const auto& event : input["unavailability_events"]) {
  1543в†’                if (event["status"] == "ACTIVE" && event["blocks_run_assignment"].get<bool>()) {
  1544в†’                    size_t train_idx = findTrainIndex(trains, event["train_id"]);
  1545в†’                    if (train_idx < trains.size()) {
  1546в†’                        for (size_t r = 0; r < routes.size(); r++) {
  1547в†’                            model.AddEquality(assign[train_idx][r], 0);
  1548в†’                        }
  1549в†’                    }
  1550в†’                }
  1551в†’            }
  1552в†’        }
  1553в†’        
  1554в†’        // NEW v2.1: Hard constraint - Route compatibility
  1555в†’        if (input.contains("route_compatibility")) {
  1556в†’            for (const auto& compat : input["route_compatibility"]) {
  1557в†’                if (!compat["is_compatible"].get<bool>()) {
  1558в†’                    size_t train_idx = findTrainIndex(trains, compat["train_id"]);
  1559в†’                    size_t route_idx = findRouteIndex(routes, compat["route_id"]);
  1560в†’                    if (train_idx < trains.size() && route_idx < routes.size()) {
  1561в†’                        model.AddEquality(assign[train_idx][route_idx], 0);
  1562в†’                    }
  1563в†’                }
  1564в†’            }
  1565в†’        }
  1566в†’        
  1567в†’        // Soft constraint: Mileage balance
  1568в†’        std::vector<IntVar> mileage_penalties;
  1569в†’        auto penalties = config["soft_constraint_penalties"];
  1570в†’        int mileage_weight = penalties["mileage_imbalance"].get<int>();
  1571в†’        
  1572в†’        for (size_t t = 0; t < trains.size(); t++) {
  1573в†’            int current = trains[t]["current_mileage"];
  1574в†’            int target = trains[t]["target_mileage"];
  1575в†’            int variance = std::abs(current - target);
  1576в†’            
  1577в†’            for (size_t r = 0; r < routes.size(); r++) {
  1578в†’                int route_km = routes[r]["expected_km"];
  1579в†’                
  1580в†’                // Penalty for assigning over-utilized train to high-km route
  1581в†’                if (current > target && route_km > 200) {
  1582в†’                    IntVar penalty = model.NewIntVar({0, variance * mileage_weight});
  1583в†’                    model.AddEquality(penalty, variance * mileage_weight)
  1584в†’                        .OnlyEnforceIf(assign[t][r]);
  1585в†’                    model.AddEquality(penalty, 0)
  1586в†’                        .OnlyEnforceIf(assign[t][r].Not());
  1587в†’                    mileage_penalties.push_back(penalty);
  1588в†’                }
  1589в†’            }
  1590в†’        }
  1591в†’        
  1592в†’        // Objective: Minimize total penalty
  1593в†’        model.Minimize(LinearExpr::Sum(mileage_penalties));
  1594в†’        
  1595в†’        // Solve
  1596в†’        SatParameters params;
  1597в†’        params.set_max_time_in_seconds(
  1598в†’            config["max_solve_time_seconds"].get<double>()
  1599в†’        );
  1600в†’        params.set_num_search_workers(
  1601в†’            config["num_workers"].get<int>()
  1602в†’        );
  1603в†’        
  1604в†’        Model cp_model;
  1605в†’        cp_model.Add(NewSatParameters(params));
  1606в†’        
  1607в†’        // Progress callback
  1608в†’        int callback_count = 0;
  1609в†’        cp_model.Add(NewFeasibleSolutionObserver([&](const CpSolverResponse& r) {
  1610в†’            callback_count++;
  1611в†’            if (callback_count % 5 == 0) {
  1612в†’                emitProgress(request_id, 
  1613в†’                    std::min(90.0, callback_count * 3.0),
  1614в†’                    r.objective_value(), true);
  1615в†’            }
  1616в†’        }));
  1617в†’        
  1618в†’        CpSolverResponse response = SolveCpModel(model.Build(), &cp_model);
  1619в†’        
  1620в†’        // Build result
  1621в†’        json result;
  1622в†’        result["type"] = "RESULT";
  1623в†’        result["request_id"] = request_id;
  1624в†’        result["solve_time_ms"] = response.wall_time() * 1000;
  1625в†’        
  1626в†’        if (response.status() == CpSolverStatus::OPTIMAL ||
  1627в†’            response.status() == CpSolverStatus::FEASIBLE) {
  1628в†’            
  1629в†’            result["status"] = response.status() == CpSolverStatus::OPTIMAL 
  1630в†’                ? "OPTIMAL" : "FEASIBLE";
  1631в†’            
  1632в†’            json assignments = json::array();
  1633в†’            
  1634в†’            for (size_t t = 0; t < trains.size(); t++) {
  1635в†’                for (size_t r = 0; r < routes.size(); r++) {
  1636в†’                    if (SolutionBooleanValue(response, assign[t][r])) {
  1637в†’                        json assignment;
  1638в†’                        assignment["train_id"] = trains[t]["id"];
  1639в†’                        assignment["route_id"] = routes[r]["id"];
  1640в†’                        assignment["score"] = computeScore(trains[t], routes[r], response);
  1641в†’                        assignment["explanation"] = generateExplanation(
  1642в†’                            trains[t], routes[r], input, response
  1643в†’                        );
  1644в†’                        assignments.push_back(assignment);
  1645в†’                    }
  1646в†’                }
  1647в†’            }
  1648в†’            
  1649в†’            result["assignments"] = assignments;
  1650в†’            result["unassigned"] = findUnassigned(trains, assignments, input);
  1651в†’            result["material_warnings"] = checkMaterialWarnings(input);
  1652в†’            result["summary"] = buildSummary(response, assignments);
  1653в†’            
  1654в†’        } else {
  1655в†’            result["status"] = "INFEASIBLE";
  1656в†’            result["assignments"] = json::array();
  1657в†’            result["unassigned"] = json::array();
  1658в†’            result["summary"] = {
  1659в†’                {"total_penalty", -1},
  1660в†’                {"trains_assigned", 0},
  1661в†’                {"trains_unassigned", trains.size()}
  1662в†’            };
  1663в†’        }
  1664в†’        
  1665в†’        return result;
  1666в†’    }
  1667в†’    
  1668в†’private:
  1669в†’    json generateExplanation(
  1670в†’        const json& train,
  1671в†’        const json& route,
  1672в†’        const json& input,
  1673в†’        const CpSolverResponse& response
  1674в†’    ) {
  1675в†’        json factors = json::array();
  1676в†’        
  1677в†’        // Mileage balance factor
  1678в†’        int current = train["current_mileage"];
  1679в†’        int target = train["target_mileage"];
  1680в†’        int variance = current - target;
